import React, { useState, useCallback, useMemo, useEffect, Suspense, lazy } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation, Navigate } from 'react-router-dom';
import { AppTab, Category, Message, AppViewMode, Article } from './types';
import { CAKENEWS_MESSAGES } from './data/mockData';
import { DataService } from './services/dataService';
import { CATEGORY_COLORS } from './constants';
import BottomNav from './components/BottomNav';
import ActionBar from './components/ActionBar';
import GlobalModalRegistry from './components/GlobalModalRegistry';
import { InteractionProvider, useInteraction } from './context/InteractionContext';
import { ModalProvider, useModal } from './context/ModalContext';
import { BroadcastProvider } from './context/BroadcastContext';
import { TranslationProvider } from './context/TranslationContext';
import { ToastProvider, useToast } from './context/ToastContext';
import { ModuleLoader } from './components/ui/Loader';
import VibeTicker from './components/ui/VibeTicker';
import BreakingNewsOverlay from './components/ui/BreakingNewsOverlay';
import AuthView from './components/AuthView';
import ErrorBoundary from './components/ui/ErrorBoundary';
import { ChevronLeft } from 'lucide-react';

// Lazy loading
const FeedView = lazy(() => import('./components/FeedView'));
const MessagesView = lazy(() => import('./components/MessagesView'));
const ProfileView = lazy(() => import('./components/ProfileView'));
const AdminView = lazy(() => import('./components/admin/AdminView'));

const GlobalSideSignature = () => (
  <div className="fixed right-0 top-[50vw] -translate-y-1/2 z-[100] pointer-events-none select-none">
    <div className="bg-black/80 border-y border-l border-white/10 py-3 px-1.5 rounded-l-lg flex flex-col items-center transition-all duration-700">
      <span className="text-[5px] font-[1000] uppercase tracking-[0.4em] text-white vertical-text-signature whitespace-nowrap">
        CAKENEWS
      </span>
    </div>
  </div>
);

const TabLoader = () => (
  <div className="w-full h-full flex items-center justify-center bg-black animate-pulse">
    <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
  </div>
);

// Wrapper pour la logique d'état principale
const MainLayout: React.FC<{ 
    viewMode: AppViewMode, 
    allArticles: Article[],
    isLoading: boolean,
    cnMessages: Message[],
    hasNewNotification: boolean,
    setViewMode: (mode: AppViewMode) => void,
    handleLogout: () => void,
    setCnMessages: React.Dispatch<React.SetStateAction<Message[]>>,
    setHasNewNotification: React.Dispatch<React.SetStateAction<boolean>>,
}> = ({ viewMode, allArticles, isLoading, cnMessages, hasNewNotification, setViewMode, handleLogout, setCnMessages, setHasNewNotification }) => {

    const navigate = useNavigate();
    const location = useLocation();
    const { toggleLike, isLiked, toggleSave, isSaved, userInterests, toggleUserInterest } = useInteraction();
    const { openModal } = useModal();
    const { showToast } = useToast();

    const [commentTrigger, setCommentTrigger] = useState(0);
    const [isCommentBlinking, setIsCommentBlinking] = useState(false);
    const [unreadCommentsCount, setUnreadCommentsCount] = useState(0);

    // FILTRES : Basé sur les préférences utilisateur (userInterests)
    const feedArticles = useMemo(() => {
        if (!userInterests || userInterests.length === 0) return [];
        return allArticles.filter(a => userInterests.includes(a.category));
    }, [allArticles, userInterests]);

    // --- LOGIQUE MÉMOIRE DE LECTURE ---
    const [lastViewedArticleId, setLastViewedArticleId] = useState<string | null>(null);

    useEffect(() => {
        // Dès qu'on est sur une URL d'article, on mémorise l'ID
        if (location.pathname.startsWith('/article/')) {
            const id = location.pathname.split('/')[2];
            setLastViewedArticleId(id);
        } else if (location.pathname === '/') {
            // Si on est à la racine, c'est le premier article
            if (allArticles.length > 0) setLastViewedArticleId(allArticles[0].id);
        }
    }, [location.pathname, allArticles]);

    // GESTION INTELLIGENTE DU BOUTON INFO
    const handleHomeNavigation = useCallback(() => {
        const isCurrentlyOnFeed = location.pathname === '/' || location.pathname.startsWith('/article/');

        if (!isCurrentlyOnFeed) {
            // CAS 1: On revient d'ailleurs (Profil, Messages...)
            // On restaure le dernier article vu
            if (lastViewedArticleId) {
                navigate(`/article/${lastViewedArticleId}`);
            } else {
                navigate('/');
            }
        } else {
            // CAS 2: On est DÉJÀ sur le flux
            // On remonte tout en haut (article le plus récent)
            if (allArticles.length > 0) {
                navigate(`/article/${allArticles[0].id}`);
            }
        }
    }, [location.pathname, lastViewedArticleId, navigate, allArticles]);
    // -----------------------------------

    const currentArticleId = useMemo(() => {
        const parts = location.pathname.split('/');
        // Supporte /article/ID et /feed/ID
        if (parts.length >= 3 && (parts[1] === 'article' || parts[1] === 'feed')) {
            return parts[2];
        }
        if (location.pathname === '/') {
            return allArticles[0]?.id;
        }
        return null;
    }, [location.pathname, allArticles]);

    const currentArticle = useMemo(() => {
        return allArticles.find(a => a.id === currentArticleId) || allArticles[0];
    }, [currentArticleId, allArticles]);

    const handleLike = useCallback(() => {
        if (!currentArticle) return;
        const isAddingLike = !isLiked(currentArticle.id);
        toggleLike(currentArticle.id);
    }, [currentArticle, isLiked, toggleLike]);

    const handleSaveAction = useCallback(() => {
        if (!currentArticle) return;
        toggleSave(currentArticle.id);
        if (!isSaved(currentArticle.id)) {
            showToast("Dossier sauvegardé", "success");
        } else {
            showToast("Retiré des favoris", "info");
        }
    }, [currentArticle, isSaved, toggleSave, showToast]);

    const handleShare = useCallback(() => {
        if (!currentArticle) return;
        openModal('SHARE', { article: currentArticle });
    }, [currentArticle, openModal]);

    const handleReportSubmitted = useCallback((ticketId: string, articleTitle: string) => {
        showToast(`Audit #${ticketId} transmis`, 'success');
        setCnMessages(prev => [{
            id: Date.now().toString(),
            sender: 'Audit CakeNews',
            avatar: 'https://picsum.photos/seed/audit/150/150',
            text: `AUDIT REÇU - Réf: ${ticketId}. Signalement pour "${articleTitle}" en cours d'analyse.`,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            isOfficial: true,
            articleId: currentArticle?.id
        }, ...prev]);
        setHasNewNotification(true);
    }, [currentArticle, setCnMessages, setHasNewNotification, showToast]);

    const handleNavigateToArticle = (id: string) => navigate(`/article/${id}`);

    const isFeedActive = location.pathname === '/' || location.pathname.startsWith('/article/') || location.pathname.startsWith('/feed');
    const accentColor = currentArticle ? (currentArticle.isExclusive ? '#ff0000' : currentArticle.isSensitive ? '#ffcc00' : CATEGORY_COLORS[currentArticle.category]) : '#ffffff';

    if (isLoading) {
        return <ModuleLoader />;
    }

    return (
        <div className="h-screen w-full bg-black text-white relative overflow-hidden flex flex-col">
            <GlobalSideSignature />
            <BreakingNewsOverlay onNavigate={handleNavigateToArticle} />

            {isFeedActive && (
                <div className="absolute top-0 left-0 right-0 z-[60]">
                    <VibeTicker />
                </div>
            )}

            <main className="flex-1 w-full overflow-hidden relative">
                <ErrorBoundary>
                    <Suspense fallback={<TabLoader />}>
                        <Routes>
                            {/* HOME FEED (GLOBAL) */}
                            <Route path="/" element={
                                <FeedView 
                                    articles={allArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />
                            <Route path="/article/:id" element={
                                <FeedView 
                                    articles={allArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />

                            {/* CUSTOM FEED (User Preferences) */}
                            <Route path="/feed" element={
                                <FeedView 
                                    articles={feedArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />
                            <Route path="/feed/:id" element={
                                <FeedView 
                                    articles={feedArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />

                            <Route path="/messages" element={
                                <MessagesView dynamicCakeNewsMessages={cnMessages} onNavigateToArticle={handleNavigateToArticle} />
                            } />
                            <Route path="/profile" element={
                                <ProfileView 
                                    preferences={userInterests} 
                                    togglePreference={toggleUserInterest} 
                                    onLogout={handleLogout}
                                />
                            } />
                            <Route path="*" element={<Navigate to="/" replace />} />
                        </Routes>
                    </Suspense>
                </ErrorBoundary>
            </main>

            <footer className="w-full flex flex-col bg-black relative z-[55] select-none pointer-events-none">
                {isFeedActive && currentArticle && (
                    <div className="pointer-events-auto pb-[60px] bg-black">
                        <ActionBar 
                            likes={currentArticle.likes + (isLiked(currentArticle.id) ? 1 : 0)}
                            comments={currentArticle.comments}
                            isLiked={isLiked(currentArticle.id)}
                            isSaved={isSaved(currentArticle.id)}
                            isCommentBlinking={isCommentBlinking}
                            hasUnreadComments={unreadCommentsCount > 0}
                            accentColor={accentColor}
                            onLike={handleLike}
                            onSave={handleSaveAction}
                            onShare={handleShare}
                            onCommentClick={() => { setCommentTrigger(prev => prev + 1); setIsCommentBlinking(false); }}
                            onReportClick={() => openModal('REPORT', { articleTitle: currentArticle.title, onReportSubmitted: handleReportSubmitted })}
                        />
                    </div>
                )}
            </footer>

            <BottomNav 
                hasNotification={hasNewNotification} 
                onHomeClick={handleHomeNavigation} 
            />
            <GlobalModalRegistry />
        </div>
    );
};

const AppContent: React.FC = () => {
    const [viewMode, setViewMode] = useState<AppViewMode>('AUTH');
    const [allArticles, setAllArticles] = useState<Article[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [cnMessages, setCnMessages] = useState<Message[]>(CAKENEWS_MESSAGES);
    const [hasNewNotification, setHasNewNotification] = useState(false);
    const { showToast } = useToast();

    // CHARGEMENT INITIAL DES DONNÉES
    useEffect(() => {
        const loadArticles = async () => {
            try {
                setIsLoading(true);
                const data = await DataService.getArticles();
                setAllArticles(data);
            } catch (error) {
                console.error("Failed to fetch articles", error);
                showToast("Erreur connexion réseau", "error");
            } finally {
                setIsLoading(false);
            }
        };

        if (viewMode !== 'AUTH') {
            loadArticles();
        }
    }, [viewMode, showToast]);

    const handleArticlePublish = async (newArticle: Article) => {
        try {
            const savedArticle = await DataService.upsertArticle(newArticle);
            if (savedArticle) {
                setAllArticles(prev => {
                    const exists = prev.findIndex(a => a.id === savedArticle.id);
                    if (exists >= 0) {
                        const updated = [...prev];
                        updated[exists] = savedArticle;
                        return updated;
                    }
                    return [savedArticle, ...prev];
                });
                showToast("Article publié sur le réseau", "success");
            }
        } catch (e) {
            showToast("Échec de la publication", "error");
        }
    };

    const handleSendSystemMessage = (target: string, content: string) => {
        const newMessage: Message = {
            id: `sys-${Date.now()}`,
            sender: 'CakeNews Team',
            avatar: 'https://picsum.photos/seed/cake/150/150',
            text: target === 'ALL' ? `[BROADCAST] ${content}` : content,
            time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}),
            isOfficial: true
        };
        setCnMessages(prev => [newMessage, ...prev]);
        setHasNewNotification(true);
    };

    if (viewMode === 'AUTH') {
        return <AuthView onLogin={(role) => setViewMode(role)} />;
    }

    if (viewMode === 'ADMIN') {
        return (
            <Suspense fallback={<TabLoader />}>
                <AdminView 
                    articles={allArticles}
                    onArticlePublish={handleArticlePublish}
                    onSendSystemMessage={handleSendSystemMessage}
                    onLogout={() => setViewMode('AUTH')}
                />
            </Suspense>
        );
    }

    return (
        <Router>
            <MainLayout 
                viewMode={viewMode}
                allArticles={allArticles}
                isLoading={isLoading}
                cnMessages={cnMessages}
                hasNewNotification={hasNewNotification}
                setViewMode={setViewMode}
                handleLogout={() => setViewMode('AUTH')}
                setCnMessages={setCnMessages}
                setHasNewNotification={setHasNewNotification}
            />
        </Router>
    );
};

const App: React.FC = () => (
  <InteractionProvider>
    <BroadcastProvider>
      <TranslationProvider>
        <ModalProvider>
          <ToastProvider> 
            <AppContent />
          </ToastProvider>
        </ModalProvider>
      </TranslationProvider>
    </BroadcastProvider>
  </InteractionProvider>
);

export default App;

import React, { useRef, useEffect, useState, useLayoutEffect } from 'react';
import { Article, AppTab } from '../types';
import ArticleCard from './ArticleCard';
import { useInteraction } from '../context/InteractionContext';
import { useNavigate, useParams } from 'react-router-dom';
import { Zap, User } from 'lucide-react';

interface FeedViewProps {
  articles: Article[];
  activeArticleIndex?: number;
  setActiveArticleIndex?: (index: number) => void;
  activeTab?: AppTab;
  onRoomEnter?: () => void;
  onUnreadCommentsChange?: (count: number) => void;
  navTarget?: { articleId: string; commentId?: string } | null;
  commentTrigger?: number;
  basePath?: string; 
}

const FeedView: React.FC<FeedViewProps> = ({
  articles,
  setActiveArticleIndex: propSetIndex,
  onRoomEnter,
  onUnreadCommentsChange,
  navTarget,
  commentTrigger,
  basePath = '/article'
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();
  const { id: paramId } = useParams();
  const { markAsRead } = useInteraction();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [containerWidth, setContainerWidth] = useState(window.innerWidth);

  // GESTION DU CAS VIDE (Pas d'articles dans le flux perso)
  if (articles.length === 0) {
      return (
          <div className="w-full h-full bg-black flex flex-col items-center justify-center p-8 text-center">
              <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center mb-6 border border-zinc-800">
                  <Zap className="w-8 h-8 text-zinc-600" />
              </div>
              <h2 className="text-xl font-[1000] uppercase text-white mb-3 tracking-tight">Flux Vide</h2>
              <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-8 leading-relaxed max-w-[200px]">
                  Sélectionnez vos intérêts dans le profil pour activer votre flux personnalisé.
              </p>
              <button 
                  onClick={() => navigate('/profile')}
                  className="px-6 py-3 bg-white text-black rounded-xl font-black uppercase text-xs tracking-widest flex items-center gap-2 hover:bg-zinc-200 transition-colors"
              >
                  <User className="w-4 h-4" /> Configurer Profil
              </button>
          </div>
      );
  }

  // Maintien de l'index synchronisé avec l'URL
  useEffect(() => {
    const targetIndex = articles.findIndex(a => a.id === paramId);
    if (targetIndex >= 0 && targetIndex !== currentIndex) {
      setCurrentIndex(targetIndex);
    } else if (!paramId && articles.length > 0) {
      // Si pas d'ID, on va au premier (ou on remplace l'URL)
      navigate(`${basePath}/${articles[0].id}`, { replace: true });
    }
  }, [paramId, articles, basePath, navigate]);

  useLayoutEffect(() => {
    const updateWidth = () => {
        if (containerRef.current) {
            setContainerWidth(containerRef.current.clientWidth);
        }
    };
    window.addEventListener('resize', updateWidth);
    updateWidth();
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  // Physique du Swipe
  const physics = useRef({
    isDragging: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    startTime: 0,
    initialTranslate: 0,
    isLockedVertical: false,   // Si vrai, on laisse le navigateur scroller (pas de swipe)
    isLockedHorizontal: false, // Si vrai, on swipe (pas de scroll)
  });

  // Mise à jour visuelle immédiate (sans animation React)
  useEffect(() => {
    if (trackRef.current) {
        trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)'; 
        trackRef.current.style.transform = `translate3d(${-currentIndex * containerWidth}px, 0, 0)`;

        const article = articles[currentIndex];
        if (article) {
            markAsRead(article.id);
            if (propSetIndex) propSetIndex(currentIndex);

            // Navigation URL silencieuse si l'index change
            if (paramId !== article.id) {
                navigate(`${basePath}/${article.id}`, { replace: true });
            }
        }
    }
  }, [currentIndex, containerWidth, articles, markAsRead, propSetIndex, navigate, basePath, paramId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onTouchStart = (e: TouchEvent) => {
        physics.current.isDragging = true;
        physics.current.startX = e.touches[0].clientX;
        physics.current.startY = e.touches[0].clientY;
        physics.current.currentX = e.touches[0].clientX;
        physics.current.startTime = Date.now();
        physics.current.isLockedVertical = false;
        physics.current.isLockedHorizontal = false;

        if (trackRef.current) {
            // On enlève la transition pour le suivi 1:1 du doigt
            trackRef.current.style.transition = 'none';
            physics.current.initialTranslate = -currentIndex * container.clientWidth;
        }
    };

    const onTouchMove = (e: TouchEvent) => {
        if (!physics.current.isDragging) return;

        const x = e.touches[0].clientX;
        const y = e.touches[0].clientY;
        const dx = x - physics.current.startX;
        const dy = y - physics.current.startY;

        // LOGIQUE DE VERROUILLAGE D'AXE
        if (!physics.current.isLockedHorizontal && !physics.current.isLockedVertical) {
            // On attend un mouvement significatif (> 8px) pour décider
            if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
                if (Math.abs(dx) > Math.abs(dy)) {
                    // Mouvement horizontal dominant -> SWIPE
                    physics.current.isLockedHorizontal = true;
                } else {
                    // Mouvement vertical dominant -> SCROLL
                    physics.current.isLockedVertical = true;
                    // On arrête de tracker le swipe, on rend la main au navigateur
                    physics.current.isDragging = false; 
                    return;
                }
            }
        }

        // Si on est verrouillé en mode swipe horizontal
        if (physics.current.isLockedHorizontal) {
            if (e.cancelable) e.preventDefault(); // Empêche le scroll vertical natif

            physics.current.currentX = x;
            if (trackRef.current) {
                // Résistance sur les bords
                let effectiveDx = dx;
                if ((currentIndex === 0 && dx > 0) || (currentIndex === articles.length - 1 && dx < 0)) {
                    effectiveDx = dx * 0.3; // Résistance élastique
                }

                const pxTranslate = physics.current.initialTranslate + effectiveDx;
                trackRef.current.style.transform = `translate3d(${pxTranslate}px, 0, 0)`;
            }
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (!physics.current.isDragging || !physics.current.isLockedHorizontal) {
            physics.current.isDragging = false;
            return;
        }

        const dx = physics.current.currentX - physics.current.startX;
        const dt = Date.now() - physics.current.startTime;
        const width = container.clientWidth;

        // Seuil pour changer de page : soit 40% de la largeur, soit un coup rapide (velocity)
        const isQuickSwipe = dt < 300 && Math.abs(dx) > 50;
        const isLongSwipe = Math.abs(dx) > width * 0.4;

        let newIndex = currentIndex;

        if ((isQuickSwipe || isLongSwipe)) {
            if (dx < 0 && currentIndex < articles.length - 1) {
                newIndex = currentIndex + 1;
            } else if (dx > 0 && currentIndex > 0) {
                newIndex = currentIndex - 1;
            }
        }

        // Animation de fin
        if (trackRef.current) {
            trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
            trackRef.current.style.transform = `translate3d(${-newIndex * width}px, 0, 0)`;
        }

        if (newIndex !== currentIndex) {
            setCurrentIndex(newIndex);
        }

        physics.current.isDragging = false;
        physics.current.isLockedHorizontal = false;
    };

    container.addEventListener('touchstart', onTouchStart, { passive: true });
    container.addEventListener('touchmove', onTouchMove, { passive: false }); // Important: passive false pour preventDefault
    container.addEventListener('touchend', onTouchEnd);
    container.addEventListener('touchcancel', onTouchEnd);

    return () => {
        container.removeEventListener('touchstart', onTouchStart);
        container.removeEventListener('touchmove', onTouchMove);
        container.removeEventListener('touchend', onTouchEnd);
        container.removeEventListener('touchcancel', onTouchEnd);
    };
  }, [currentIndex, articles.length]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-black overflow-hidden relative"
      // touch-action: pan-y permet au navigateur de gérer le scroll vertical par défaut
      // notre JS prendra le relais (preventDefault) uniquement si on détecte un swipe horizontal
      style={{ touchAction: 'pan-y' }} 
    >
      <div 
        ref={trackRef}
        className="h-full flex will-change-transform"
        style={{ 
            width: `${articles.length * 100}%`, 
            transform: `translate3d(${-currentIndex * containerWidth}px, 0, 0)` 
        }}
      >
        {articles.map((article, index) => {
            // Optimisation : Ne rendre que l'article courant et ses voisins immédiats
            const distance = Math.abs(currentIndex - index);
            const shouldRender = distance <= 1;

            return (
                <div 
                    key={article.id}
                    className="h-full relative"
                    style={{ width: `${100 / articles.length}%` }}
                >
                    {shouldRender ? (
                        <ArticleCard 
                            article={article}
                            isActive={index === currentIndex}
                            isPreloading={index !== currentIndex}
                            onRoomEnter={onRoomEnter}
                            onUnreadCommentsChange={onUnreadCommentsChange}
                            navTarget={index === currentIndex ? navTarget : null}
                            onNavigateNext={() => {
                                if (index < articles.length - 1) setCurrentIndex(index + 1);
                            }}
                            commentTrigger={index === currentIndex ? commentTrigger : 0}
                        />
                    ) : (
                        <div className="w-full h-full bg-black" />
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default React.memo(FeedView);

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
          return this.props.fallback;
      }
      return (
        <div className="w-full h-full flex flex-col items-center justify-center bg-black p-8 text-center">
          <AlertTriangle className="w-16 h-16 text-red-600 mb-6" />
          <h2 className="text-xl font-black uppercase text-white mb-2 tracking-tight">Signal Interrompu</h2>
          <p className="text-white/50 text-xs font-mono mb-8 uppercase">Une erreur critique est survenue dans ce module.</p>

          <button 
            onClick={() => window.location.reload()}
