import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Home, Zap, MessageCircle, User } from 'lucide-react';
import { useInteraction } from '../context/InteractionContext';

interface BottomNavProps {
  hasNotification?: boolean;
  onHomeClick?: () => void;
}

const BottomNav: React.FC<BottomNavProps> = ({ hasNotification, onHomeClick }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const { triggerHaptic } = useInteraction();

  // Logique précise pour déterminer l'onglet actif
  const isActive = (path: string) => {
    if (path === '/') {
      return location.pathname === '/' || location.pathname.startsWith('/article/');
    }
    return location.pathname.startsWith(path);
  };

  const navItems = [
    { 
      id: 'home', 
      label: 'UNE', 
      icon: Home, 
      path: '/',
      action: onHomeClick 
    },
    { 
      id: 'feed', 
      label: 'FLUX', 
      icon: Zap, 
      path: '/feed',
      action: () => navigate('/feed')
    },
    { 
      id: 'messages', 
      label: 'CHATS', 
      icon: MessageCircle, 
      path: '/messages',
      action: () => navigate('/messages'),
      hasBadge: hasNotification
    },
    { 
      id: 'profile', 
      label: 'PROFIL', 
      icon: User, 
      path: '/profile',
      action: () => navigate('/profile')
    }
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-[100] bg-black/95 backdrop-blur-xl border-t border-white/10 pb-safe transition-all duration-300">
      <div className="flex justify-around items-center h-[64px] px-2">
        {navItems.map((item) => {
          const active = isActive(item.path);
          const Icon = item.icon;

          return (
            <button
              key={item.id}
              onClick={() => {
                triggerHaptic('light');
                if (item.action) item.action();
              }}
              className="group relative flex flex-col items-center justify-center flex-1 h-full gap-1 active:scale-90 transition-transform duration-200 outline-none"
            >
              {/* Conteneur Icône avec animation d'état */}
              <div className={`relative p-1.5 rounded-2xl transition-all duration-300 ${active ? 'bg-white/10 translate-y-0' : 'bg-transparent translate-y-1'}`}>
                <Icon 
                  className={`w-6 h-6 transition-all duration-300 ${
                    active ? 'text-white fill-white/20' : 'text-zinc-600 group-hover:text-zinc-400'
                  }`} 
                  strokeWidth={active ? 2.5 : 2}
                />

                {/* Badge de Notification */}
                {item.hasBadge && (
                  <span className="absolute top-0 right-0 w-3 h-3 bg-[#ff0000] border-2 border-black rounded-full z-10 animate-pulse shadow-[0_0_8px_rgba(255,0,0,0.5)]" />
                )}
              </div>

              {/* Label */}
              <span className={`text-[9px] font-[1000] uppercase tracking-widest transition-all duration-300 ${
                active ? 'text-white opacity-100 translate-y-0' : 'text-zinc-600 opacity-0 translate-y-2 absolute bottom-2'
              }`}>
                {item.label}
              </span>

              {/* Indicateur actif lumineux au sol */}
              <div className={`absolute bottom-0 w-8 h-[2px] rounded-full bg-gradient-to-r from-transparent via-[#ff0000] to-transparent transition-opacity duration-300 ${active ? 'opacity-100' : 'opacity-0'}`} />
            </button>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNav;

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
          return this.props.fallback;
      }
      return (
        <div className="w-full h-full flex flex-col items-center justify-center bg-black p-8 text-center">
          <AlertTriangle className="w-16 h-16 text-red-600 mb-6" />
          <h2 className="text-xl font-black uppercase text-white mb-2 tracking-tight">Signal Interrompu</h2>
          <p className="text-white/50 text-xs font-mono mb-8 uppercase">Une erreur critique est survenue dans ce module.</p>

          <button 
            onClick={() => window.location.reload()}
            className="flex items-center gap-2 px-6 py-3 bg-white text-black rounded-xl font-black uppercase text-xs tracking-widest active:scale-95 transition-transform"
          >
            <RefreshCw className="w-4 h-4" /> Relancer l'app
          </button>

          {process.env.NODE_ENV === 'development' && (
              <pre className="mt-8 p-4 bg-zinc-900 rounded-lg text-[10px] text-red-400 text-left w-full overflow-auto max-h-40">
                  {this.state.error?.toString()}
              </pre>
          )}
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import React, { useRef, useEffect, useState, useLayoutEffect } from 'react';
import { Article, AppTab, Category } from '../types';
import ArticleCard from './ArticleCard';
import { useInteraction } from '../context/InteractionContext';
import { useNavigate, useParams } from 'react-router-dom';
import { Zap, User, SlidersHorizontal, X, Check, Filter } from 'lucide-react';
import { CATEGORIES, CATEGORY_COLORS, getTextColor } from '../constants';
import { useTranslation } from '../context/TranslationContext';

interface FeedViewProps {
  articles: Article[];
  activeArticleIndex?: number;
  setActiveArticleIndex?: (index: number) => void;
  activeTab?: AppTab;
  onRoomEnter?: () => void;
  onUnreadCommentsChange?: (count: number) => void;
  navTarget?: { articleId: string; commentId?: string } | null;
  commentTrigger?: number;
  basePath?: string; 
}

const FeedView: React.FC<FeedViewProps> = ({
  articles,
  setActiveArticleIndex: propSetIndex,
  onRoomEnter,
  onUnreadCommentsChange,
  navTarget,
  commentTrigger,
  basePath = '/article'
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();
  const { id: paramId } = useParams();
  const { markAsRead, userInterests, toggleUserInterest } = useInteraction();
  const { t } = useTranslation();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [containerWidth, setContainerWidth] = useState(window.innerWidth);
  const [showConfig, setShowConfig] = useState(false);

  // Maintien de l'index synchronisé avec l'URL
  useEffect(() => {
    const targetIndex = articles.findIndex(a => a.id === paramId);
    if (targetIndex >= 0 && targetIndex !== currentIndex) {
      setCurrentIndex(targetIndex);
    } else if (!paramId && articles.length > 0) {
      // Si pas d'ID, on va au premier (ou on remplace l'URL)
      navigate(`${basePath}/${articles[0].id}`, { replace: true });
    }
  }, [paramId, articles, basePath, navigate]);

  useLayoutEffect(() => {
    const updateWidth = () => {
        if (containerRef.current) {
            setContainerWidth(containerRef.current.clientWidth);
        }
    };
    window.addEventListener('resize', updateWidth);
    updateWidth();
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  // Physique du Swipe
  const physics = useRef({
    isDragging: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    startTime: 0,
    initialTranslate: 0,
    isLockedVertical: false,   // Si vrai, on laisse le navigateur scroller (pas de swipe)
    isLockedHorizontal: false, // Si vrai, on swipe (pas de scroll)
  });

  // Mise à jour visuelle immédiate (sans animation React)
  useEffect(() => {
    if (trackRef.current) {
        trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)'; 
        trackRef.current.style.transform = `translate3d(${-currentIndex * containerWidth}px, 0, 0)`;

        const article = articles[currentIndex];
        if (article) {
            markAsRead(article.id);
            if (propSetIndex) propSetIndex(currentIndex);

            // Navigation URL silencieuse si l'index change
            if (paramId !== article.id) {
                navigate(`${basePath}/${article.id}`, { replace: true });
            }
        }
    }
  }, [currentIndex, containerWidth, articles, markAsRead, propSetIndex, navigate, basePath, paramId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onTouchStart = (e: TouchEvent) => {
        physics.current.isDragging = true;
        physics.current.startX = e.touches[0].clientX;
        physics.current.startY = e.touches[0].clientY;
        physics.current.currentX = e.touches[0].clientX;
        physics.current.startTime = Date.now();
        physics.current.isLockedVertical = false;
        physics.current.isLockedHorizontal = false;

        if (trackRef.current) {
            // On enlève la transition pour le suivi 1:1 du doigt
            trackRef.current.style.transition = 'none';
            physics.current.initialTranslate = -currentIndex * container.clientWidth;
        }
    };

    const onTouchMove = (e: TouchEvent) => {
        if (!physics.current.isDragging) return;

        const x = e.touches[0].clientX;
        const y = e.touches[0].clientY;
        const dx = x - physics.current.startX;
        const dy = y - physics.current.startY;

        // LOGIQUE DE VERROUILLAGE D'AXE
        if (!physics.current.isLockedHorizontal && !physics.current.isLockedVertical) {
            // On attend un mouvement significatif (> 8px) pour décider
            if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
                if (Math.abs(dx) > Math.abs(dy)) {
                    // Mouvement horizontal dominant -> SWIPE
                    physics.current.isLockedHorizontal = true;
                } else {
                    // Mouvement vertical dominant -> SCROLL
                    physics.current.isLockedVertical = true;
                    // On arrête de tracker le swipe, on rend la main au navigateur
                    physics.current.isDragging = false; 
                    return;
                }
            }
        }

        // Si on est verrouillé en mode swipe horizontal
        if (physics.current.isLockedHorizontal) {
            if (e.cancelable) e.preventDefault(); // Empêche le scroll vertical natif

            physics.current.currentX = x;
            if (trackRef.current) {
                // Résistance sur les bords
                let effectiveDx = dx;
                if ((currentIndex === 0 && dx > 0) || (currentIndex === articles.length - 1 && dx < 0)) {
                    effectiveDx = dx * 0.3; // Résistance élastique
                }

                const pxTranslate = physics.current.initialTranslate + effectiveDx;
                trackRef.current.style.transform = `translate3d(${pxTranslate}px, 0, 0)`;
            }
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (!physics.current.isDragging || !physics.current.isLockedHorizontal) {
            physics.current.isDragging = false;
            return;
        }

        const dx = physics.current.currentX - physics.current.startX;
        const dt = Date.now() - physics.current.startTime;
        const width = container.clientWidth;

        // Seuil pour changer de page : soit 40% de la largeur, soit un coup rapide (velocity)
        const isQuickSwipe = dt < 300 && Math.abs(dx) > 50;
        const isLongSwipe = Math.abs(dx) > width * 0.4;

        let newIndex = currentIndex;

        if ((isQuickSwipe || isLongSwipe)) {
            if (dx < 0 && currentIndex < articles.length - 1) {
                newIndex = currentIndex + 1;
            } else if (dx > 0 && currentIndex > 0) {
                newIndex = currentIndex - 1;
            }
        }

        // Animation de fin
        if (trackRef.current) {
            trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
            trackRef.current.style.transform = `translate3d(${-newIndex * width}px, 0, 0)`;
        }

        if (newIndex !== currentIndex) {
            setCurrentIndex(newIndex);
        }

        physics.current.isDragging = false;
        physics.current.isLockedHorizontal = false;
    };

    container.addEventListener('touchstart', onTouchStart, { passive: true });
    container.addEventListener('touchmove', onTouchMove, { passive: false }); // Important: passive false pour preventDefault
    container.addEventListener('touchend', onTouchEnd);
    container.addEventListener('touchcancel', onTouchEnd);

    return () => {
        container.removeEventListener('touchstart', onTouchStart);
        container.removeEventListener('touchmove', onTouchMove);
        container.removeEventListener('touchend', onTouchEnd);
        container.removeEventListener('touchcancel', onTouchEnd);
    };
  }, [currentIndex, articles.length]);

  // --- CONFIGURATEUR DE FLUX (COMPOSANT INTERNE) ---
  const FeedConfigurator = () => (
    <div className="w-full h-full flex flex-col p-6 overflow-y-auto">
        <div className="flex items-center justify-between mb-8">
            <div>
                <h3 className="text-xl font-[1000] uppercase text-white tracking-tight">Votre Ligne Éditoriale</h3>
                <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mt-1">
                    Sélectionnez ce qui doit apparaître dans votre flux.
                </p>
            </div>
            {articles.length > 0 && (
                <button onClick={() => setShowConfig(false)} className="p-2 bg-zinc-800 rounded-full text-white">
                    <X className="w-5 h-5" />
                </button>
            )}
        </div>

        <div className="grid grid-cols-2 gap-3 mb-8">
            {CATEGORIES.map((cat) => {
              const isSelected = userInterests.includes(cat);
              const catColor = CATEGORY_COLORS[cat];
              const textColor = getTextColor(cat);

              return (
                <button
                  key={cat}
                  onClick={() => toggleUserInterest(cat)}
                  className={`py-4 px-4 font-[1000] uppercase text-xs border-2 transition-all flex items-center justify-between rounded-xl ${
                    isSelected 
                      ? `${textColor} border-transparent` 
                      : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'
                  }`}
                  style={{ backgroundColor: isSelected ? catColor : undefined }}
                >
                  {cat}
                  {isSelected && <Check className="w-3 h-3" />}
                </button>
              );
            })}
        </div>

        {articles.length > 0 ? (
            <button 
                onClick={() => setShowConfig(false)}
                className="mt-auto w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl flex items-center justify-center gap-2 active:scale-95 transition-transform"
            >
                <Check className="w-4 h-4" /> Valider mon flux
            </button>
        ) : (
            <div className="mt-auto text-center p-4 bg-zinc-900 border border-zinc-800 rounded-xl">
                <Filter className="w-6 h-6 text-zinc-600 mx-auto mb-2" />
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">
                    {userInterests.length === 0 ? "Sélectionnez au moins un intérêt." : "Aucun article disponible pour cette sélection."}
                </p>
            </div>
        )}
    </div>
  );

  // GESTION DU CAS VIDE (Pas d'articles filtrés)
  if (articles.length === 0) {
      return (
          <div className="w-full h-full bg-black relative">
              <FeedConfigurator />
          </div>
      );
  }

  // --- RENDU PRINCIPAL ---
  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-black overflow-hidden relative"
      // touch-action: pan-y permet au navigateur de gérer le scroll vertical par défaut
      style={{ touchAction: 'pan-y' }} 
    >
      {/* BOUTON CONFIGURATION FLOTTANT */}
      {basePath === '/feed' && (
          <div className="absolute top-4 right-4 z-50">
              <button 
                  onClick={() => setShowConfig(true)}
                  className="p-3 bg-black/50 backdrop-blur-md border border-white/10 rounded-full text-white/70 hover:text-white hover:bg-black/70 transition-all active:scale-95 shadow-lg"
              >
                  <SlidersHorizontal className="w-5 h-5" />
              </button>
          </div>
      )}

      {/* OVERLAY CONFIGURATION */}
      {showConfig && (
          <div className="absolute inset-0 z-[100] bg-black/95 backdrop-blur-xl animate-in fade-in duration-200">
              <FeedConfigurator />
          </div>
      )}

      {/* FLUX D'ARTICLES */}
      <div 
        ref={trackRef}
        className="h-full flex will-change-transform"
        style={{ 
            width: `${articles.length * 100}%`, 
            transform: `translate3d(${-currentIndex * containerWidth}px, 0, 0)` 
        }}
      >
        {articles.map((article, index) => {
            // Optimisation : Ne rendre que l'article courant et ses voisins immédiats
            const distance = Math.abs(currentIndex - index);
            const shouldRender = distance <= 1;

            return (
                <div 
                    key={article.id}
                    className="h-full relative"
                    style={{ width: `${100 / articles.length}%` }}
                >
                    {shouldRender ? (
                        <ArticleCard 
                            article={article}
                            isActive={index === currentIndex}
                            isPreloading={index !== currentIndex}
                            onRoomEnter={onRoomEnter}
                            onUnreadCommentsChange={onUnreadCommentsChange}
                            navTarget={index === currentIndex ? navTarget : null}
                            onNavigateNext={() => {
                                if (index < articles.length - 1) setCurrentIndex(index + 1);
                            }}
                            commentTrigger={index === currentIndex ? commentTrigger : 0}
                        />
                    ) : (
                        <div className="w-full h-full bg-black" />
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default React.memo(FeedView);

