import React, { useRef, useEffect, useState, useLayoutEffect } from 'react';
import { Article, AppTab, Category } from '../types';
import ArticleCard from './ArticleCard';
import { useInteraction } from '../context/InteractionContext';
import { useNavigate, useParams } from 'react-router-dom';
import { SlidersHorizontal, X, Check, Filter, ShieldAlert, AlertTriangle, Info, ShieldCheck } from 'lucide-react';
import { CATEGORIES, CATEGORY_COLORS, getTextColor, THEME_GROUPS } from '../constants';
import { useTranslation } from '../context/TranslationContext';

interface FeedViewProps {
  articles: Article[];
  activeArticleIndex?: number;
  setActiveArticleIndex?: (index: number) => void;
  activeTab?: AppTab;
  onRoomEnter?: () => void;
  onUnreadCommentsChange?: (count: number) => void;
  navTarget?: { articleId: string; commentId?: string } | null;
  commentTrigger?: number;
  basePath?: string; 
}

const FeedView: React.FC<FeedViewProps> = ({
  articles,
  setActiveArticleIndex: propSetIndex,
  onRoomEnter,
  onUnreadCommentsChange,
  navTarget,
  commentTrigger,
  basePath = '/article'
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();
  const { id: paramId } = useParams();
  const { markAsRead, userInterests, toggleUserInterest } = useInteraction();
  const { t } = useTranslation();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [containerWidth, setContainerWidth] = useState(window.innerWidth);
  const [showConfig, setShowConfig] = useState(false);

  // --- SYNC URL & INDEX & FILTRES ---
  useEffect(() => {
    // Cas 1 : Aucun article disponible (Filtres trop restrictifs)
    if (articles.length === 0) return;

    // Trouver l'index de l'article demandé dans l'URL
    const targetIndex = articles.findIndex(a => a.id === paramId);

    if (targetIndex >= 0) {
      // L'article existe dans le flux actuel
      if (targetIndex !== currentIndex) {
        setCurrentIndex(targetIndex);
      }
    } else {
      // L'article de l'URL n'est pas dans le flux (ex: filtre modifié)
      // On redirige vers le premier article disponible pour éviter l'écran noir
      const newTargetId = articles[0].id;
      if (paramId !== newTargetId) {
          navigate(`${basePath}/${newTargetId}`, { replace: true });
          setCurrentIndex(0);
      }
    }
  }, [paramId, articles, basePath, navigate]);

  useLayoutEffect(() => {
    const updateWidth = () => {
        if (containerRef.current) {
            setContainerWidth(containerRef.current.clientWidth);
        }
    };
    window.addEventListener('resize', updateWidth);
    updateWidth();
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  // Physique du Swipe
  const physics = useRef({
    isDragging: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    startTime: 0,
    initialTranslate: 0,
    isLockedVertical: false,
    isLockedHorizontal: false,
  });

  // Mise à jour visuelle immédiate (sans animation React pour perf)
  useEffect(() => {
    if (trackRef.current) {
        trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)'; 
        trackRef.current.style.transform = `translate3d(${-currentIndex * containerWidth}px, 0, 0)`;

        const article = articles[currentIndex];
        if (article) {
            markAsRead(article.id);
            if (propSetIndex) propSetIndex(currentIndex);

            // Navigation URL silencieuse si l'index change localement
            if (paramId !== article.id) {
                navigate(`${basePath}/${article.id}`, { replace: true });
            }
        }
    }
  }, [currentIndex, containerWidth, articles, markAsRead, propSetIndex, navigate, basePath, paramId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onTouchStart = (e: TouchEvent) => {
        physics.current.isDragging = true;
        physics.current.startX = e.touches[0].clientX;
        physics.current.startY = e.touches[0].clientY;
        physics.current.currentX = e.touches[0].clientX;
        physics.current.startTime = Date.now();
        physics.current.isLockedVertical = false;
        physics.current.isLockedHorizontal = false;

        if (trackRef.current) {
            trackRef.current.style.transition = 'none';
            physics.current.initialTranslate = -currentIndex * container.clientWidth;
        }
    };

    const onTouchMove = (e: TouchEvent) => {
        if (!physics.current.isDragging) return;

        const x = e.touches[0].clientX;
        const y = e.touches[0].clientY;
        const dx = x - physics.current.startX;
        const dy = y - physics.current.startY;

        if (!physics.current.isLockedHorizontal && !physics.current.isLockedVertical) {
            if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
                if (Math.abs(dx) > Math.abs(dy)) {
                    physics.current.isLockedHorizontal = true;
                } else {
                    physics.current.isLockedVertical = true;
                    physics.current.isDragging = false; 
                    return;
                }
            }
        }

        if (physics.current.isLockedHorizontal) {
            if (e.cancelable) e.preventDefault();

            physics.current.currentX = x;
            if (trackRef.current) {
                let effectiveDx = dx;
                // Résistance élastique aux bords
                if ((currentIndex === 0 && dx > 0) || (currentIndex === articles.length - 1 && dx < 0)) {
                    effectiveDx = dx * 0.3;
                }
                const pxTranslate = physics.current.initialTranslate + effectiveDx;
                trackRef.current.style.transform = `translate3d(${pxTranslate}px, 0, 0)`;
            }
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (!physics.current.isDragging || !physics.current.isLockedHorizontal) {
            physics.current.isDragging = false;
            return;
        }

        const dx = physics.current.currentX - physics.current.startX;
        const dt = Date.now() - physics.current.startTime;
        const width = container.clientWidth;

        const isQuickSwipe = dt < 300 && Math.abs(dx) > 50;
        const isLongSwipe = Math.abs(dx) > width * 0.4;

        let newIndex = currentIndex;

        if ((isQuickSwipe || isLongSwipe)) {
            if (dx < 0 && currentIndex < articles.length - 1) {
                newIndex = currentIndex + 1;
            } else if (dx > 0 && currentIndex > 0) {
                newIndex = currentIndex - 1;
            }
        }

        if (trackRef.current) {
            trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
            trackRef.current.style.transform = `translate3d(${-newIndex * width}px, 0, 0)`;
        }

        if (newIndex !== currentIndex) {
            setCurrentIndex(newIndex);
        }

        physics.current.isDragging = false;
        physics.current.isLockedHorizontal = false;
    };

    container.addEventListener('touchstart', onTouchStart, { passive: true });
    container.addEventListener('touchmove', onTouchMove, { passive: false });
    container.addEventListener('touchend', onTouchEnd);
    container.addEventListener('touchcancel', onTouchEnd);

    return () => {
        container.removeEventListener('touchstart', onTouchStart);
        container.removeEventListener('touchmove', onTouchMove);
        container.removeEventListener('touchend', onTouchEnd);
        container.removeEventListener('touchcancel', onTouchEnd);
    };
  }, [currentIndex, articles.length]);

  // --- CONFIGURATEUR DE FLUX (Refonte) ---
  const FeedConfigurator = () => (
    <div className="w-full h-full flex flex-col bg-zinc-950 pb-safe relative">
        {/* Header */}
        <div className="p-6 pt-12 pb-4 bg-black border-b border-zinc-800 sticky top-0 z-10 flex items-center justify-between">
            <div>
                <h3 className="text-2xl font-[1000] uppercase text-white tracking-tighter">Votre Algorithme</h3>
                <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mt-1">
                    Cakenews ne décide pas pour vous.
                </p>
            </div>
            {articles.length > 0 && (
                <button onClick={() => setShowConfig(false)} className="p-2 bg-zinc-900 rounded-full text-white hover:bg-zinc-800 transition-colors border border-zinc-800">
                    <X className="w-6 h-6" />
                </button>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">

            {/* SECTION 1: THEMES GENERAUX */}
            <div>
                <div className="flex items-center gap-2 mb-4 text-zinc-400">
                    <Filter className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">Cœur de l'info</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    {THEME_GROUPS.GENERAL.map((cat) => (
                        <CategoryToggle key={cat} category={cat} />
                    ))}
                </div>
            </div>

            {/* SECTION 2: LOISIRS */}
            <div>
                <div className="flex items-center gap-2 mb-4 text-zinc-400">
                    <Info className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">Intérêts Personnels</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    {THEME_GROUPS.LOISIRS.map((cat) => (
                        <CategoryToggle key={cat} category={cat} />
                    ))}
                </div>
            </div>

            {/* SECTION 3: CONTENU SENSIBLE (SÉCURITÉ) */}
            <div className="bg-red-900/10 border border-red-500/20 rounded-[32px] p-6">
                <div className="flex items-start gap-4 mb-6">
                    <div className="p-3 bg-red-500/20 rounded-xl text-red-500">
                        <ShieldAlert className="w-6 h-6" />
                    </div>
                    <div>
                        <h4 className="text-white font-[1000] uppercase text-sm tracking-wide">Filtres de Sensibilité</h4>
                        <p className="text-red-300/60 text-[10px] font-bold mt-1 leading-relaxed">
                            Cochez ces options uniquement si vous consentez à voir du contenu difficile ou choquant. Par défaut, CakeNews vous protège.
                        </p>
                    </div>
                </div>
                <div className="grid grid-cols-1 gap-2">
                    {THEME_GROUPS.SENSITIVE.map((cat) => (
                        <SensitiveToggle key={cat} category={cat} />
                    ))}
                </div>
            </div>

            <div className="h-20"></div> {/* Spacer */}
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-black border-t border-zinc-800 absolute bottom-0 left-0 right-0 z-20">
            {articles.length > 0 ? (
                <button 
                    onClick={() => setShowConfig(false)}
                    className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl flex items-center justify-center gap-3 active:scale-95 transition-transform hover:bg-zinc-200"
                >
                    <Check className="w-4 h-4" /> Appliquer mes choix
                </button>
            ) : (
                <div className="text-center p-4">
                    <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">
                        Sélectionnez au moins une catégorie ci-dessus.
                    </p>
                </div>
            )}
        </div>
    </div>
  );

  // Helper pour les boutons simples
  const CategoryToggle = ({ category }: { category: Category }) => {
      const isSelected = userInterests.includes(category);
      const catColor = CATEGORY_COLORS[category];

      return (
        <button
          onClick={() => toggleUserInterest(category)}
          className={`h-16 px-4 font-[1000] uppercase text-[11px] border transition-all flex items-center justify-between rounded-xl active:scale-95 ${
            isSelected 
              ? `bg-white text-black border-transparent shadow-lg` 
              : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'
          }`}
        >
          {t(`CAT_${category.toUpperCase()}`, category)}
          <div className={`w-3 h-3 rounded-full ${isSelected ? 'bg-black' : 'bg-zinc-700'}`} style={{ backgroundColor: isSelected ? catColor : undefined }}></div>
        </button>
      );
  };

  // Helper pour les switchs sensibles
  const SensitiveToggle = ({ category }: { category: Category }) => {
      const isSelected = userInterests.includes(category);

      return (
        <button
          onClick={() => toggleUserInterest(category)}
          className={`p-4 flex items-center justify-between rounded-xl border transition-all active:scale-[0.98] ${
              isSelected 
              ? 'bg-red-500/10 border-red-500 text-white' 
              : 'bg-black border-zinc-800 text-zinc-600 hover:border-zinc-700'
          }`}
        >
            <div className="flex items-center gap-3">
                <AlertTriangle className={`w-4 h-4 ${isSelected ? 'text-red-500' : 'opacity-20'}`} />
                <span className="font-[1000] uppercase text-[10px] tracking-widest">
                    {t(`CAT_${category.toUpperCase()}`, category)}
                </span>
            </div>

            {/* Switch UI */}
            <div className={`w-10 h-6 rounded-full relative transition-colors ${isSelected ? 'bg-red-500' : 'bg-zinc-800'}`}>
                <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${isSelected ? 'translate-x-4' : ''}`}></div>
            </div>
        </button>
      );
  };

  // GESTION DU CAS VIDE (Pas d'articles filtrés)
  if (articles.length === 0) {
      return (
          <div className="w-full h-full bg-black relative z-[200]">
              <FeedConfigurator />
          </div>
      );
  }

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-black overflow-hidden relative"
      style={{ touchAction: 'pan-y' }} 
    >
      {/* BOUTON CONFIGURATION FLOTTANT (Seulement sur le flux perso) */}
      {basePath === '/feed' && (
          <div className="absolute top-4 right-4 z-50">
              <button 
                  onClick={() => setShowConfig(true)}
                  className="p-3 bg-black/50 backdrop-blur-md border border-white/10 rounded-full text-white/70 hover:text-white hover:bg-black/70 transition-all active:scale-95 shadow-lg group"
              >
                  <SlidersHorizontal className="w-5 h-5 group-hover:rotate-180 transition-transform duration-500" />
              </button>
          </div>
      )}

      {/* OVERLAY CONFIGURATION */}
      {showConfig && (
          <div className="absolute inset-0 z-[100] bg-black animate-in fade-in duration-200">
              <FeedConfigurator />
          </div>
      )}

      {/* FLUX D'ARTICLES */}
      <div 
        ref={trackRef}
        className="h-full flex will-change-transform"
        style={{ 
            width: `${articles.length * 100}%`, 
            transform: `translate3d(${-currentIndex * containerWidth}px, 0, 0)` 
        }}
      >
        {articles.map((article, index) => {
            // Optimisation : Ne rendre que l'article courant et ses voisins
            const distance = Math.abs(currentIndex - index);
            const shouldRender = distance <= 1;

            return (
                <div 
                    key={article.id}
                    className="h-full relative"
                    style={{ width: `${100 / articles.length}%` }}
                >
                    {shouldRender ? (
                        <ArticleCard 
                            article={article}
                            isActive={index === currentIndex}
                            isPreloading={index !== currentIndex}
                            onRoomEnter={onRoomEnter}
                            onUnreadCommentsChange={onUnreadCommentsChange}
                            navTarget={index === currentIndex ? navTarget : null}
                            onNavigateNext={() => {
                                if (index < articles.length - 1) setCurrentIndex(index + 1);
                            }}
                            commentTrigger={index === currentIndex ? commentTrigger : 0}
                        />
                    ) : (
                        <div className="w-full h-full bg-black" />
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default React.memo(FeedView);

import React, { useRef, useEffect, useState, useLayoutEffect } from 'react';
import { Article, AppTab, Category } from '../types';
import ArticleCard from './ArticleCard';
import { useInteraction } from '../context/InteractionContext';
import { useNavigate, useParams } from 'react-router-dom';
import { SlidersHorizontal, X, Check, Filter, ShieldAlert, AlertTriangle, Info, ShieldCheck } from 'lucide-react';
import { CATEGORIES, CATEGORY_COLORS, getTextColor, THEME_GROUPS } from '../constants';
import { useTranslation } from '../context/TranslationContext';

interface FeedViewProps {
  articles: Article[];
  activeArticleIndex?: number;
  setActiveArticleIndex?: (index: number) => void;
  activeTab?: AppTab;
  onRoomEnter?: () => void;
  onUnreadCommentsChange?: (count: number) => void;
  navTarget?: { articleId: string; commentId?: string } | null;
  commentTrigger?: number;
  basePath?: string; 
}

// Helper pour les boutons simples - Moved outside to fix type errors with key prop
const CategoryToggle = React.memo(({ 
  category, 
  isSelected, 
  onToggle, 
  t 
}: { 
  category: Category; 
  isSelected: boolean; 
  onToggle: (c: Category) => void; 
  t: (k: string, d?: string) => string; 
}) => {
  const catColor = CATEGORY_COLORS[category];

  return (
    <button
      onClick={() => onToggle(category)}
      className={`h-16 px-4 font-[1000] uppercase text-[11px] border transition-all flex items-center justify-between rounded-xl active:scale-95 ${
        isSelected 
          ? `bg-white text-black border-transparent shadow-lg` 
          : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'
      }`}
    >
      {t(`CAT_${category.toUpperCase()}`, category)}
      <div className={`w-3 h-3 rounded-full ${isSelected ? 'bg-black' : 'bg-zinc-700'}`} style={{ backgroundColor: isSelected ? catColor : undefined }}></div>
    </button>
  );
});

// Helper pour les switchs sensibles - Moved outside
const SensitiveToggle = React.memo(({ 
  category, 
  isSelected, 
  onToggle, 
  t 
}: { 
  category: Category; 
  isSelected: boolean; 
  onToggle: (c: Category) => void; 
  t: (k: string, d?: string) => string; 
}) => {
  return (
    <button
      onClick={() => onToggle(category)}
      className={`p-4 flex items-center justify-between rounded-xl border transition-all active:scale-[0.98] ${
          isSelected 
          ? 'bg-red-500/10 border-red-500 text-white' 
          : 'bg-black border-zinc-800 text-zinc-600 hover:border-zinc-700'
      }`}
    >
        <div className="flex items-center gap-3">
            <AlertTriangle className={`w-4 h-4 ${isSelected ? 'text-red-500' : 'opacity-20'}`} />
            <span className="font-[1000] uppercase text-[10px] tracking-widest">
                {t(`CAT_${category.toUpperCase()}`, category)}
            </span>
        </div>

        <div className={`w-10 h-6 rounded-full relative transition-colors ${isSelected ? 'bg-red-500' : 'bg-zinc-800'}`}>
            <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${isSelected ? 'translate-x-4' : ''}`}></div>
        </div>
    </button>
  );
});

const FeedView: React.FC<FeedViewProps> = ({
  articles,
  setActiveArticleIndex: propSetIndex,
  onRoomEnter,
  onUnreadCommentsChange,
  navTarget,
  commentTrigger,
  basePath = '/article'
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();
  const { id: paramId } = useParams();
  const { markAsRead, userInterests, toggleUserInterest } = useInteraction();
  const { t } = useTranslation();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [containerWidth, setContainerWidth] = useState(window.innerWidth);
  const [showConfig, setShowConfig] = useState(false);

  // --- SYNC URL & INDEX & FILTRES ---
  useEffect(() => {
    // Cas 1 : Aucun article disponible (Filtres trop restrictifs)
    if (articles.length === 0) return;

    // Trouver l'index de l'article demandé dans l'URL
    const targetIndex = articles.findIndex(a => a.id === paramId);

    if (targetIndex >= 0) {
      // L'article existe dans le flux actuel
      if (targetIndex !== currentIndex) {
        setCurrentIndex(targetIndex);
      }
    } else {
      // L'article de l'URL n'est pas dans le flux (ex: filtre modifié)
      // On redirige vers le premier article disponible pour éviter l'écran noir
      const newTargetId = articles[0].id;
      if (paramId !== newTargetId) {
          navigate(`${basePath}/${newTargetId}`, { replace: true });
          setCurrentIndex(0);
      }
    }
  }, [paramId, articles, basePath, navigate]);

  useLayoutEffect(() => {
    const updateWidth = () => {
        if (containerRef.current) {
            setContainerWidth(containerRef.current.clientWidth);
        }
    };
    window.addEventListener('resize', updateWidth);
    updateWidth();
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  // Physique du Swipe
  const physics = useRef({
    isDragging: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    startTime: 0,
    initialTranslate: 0,
    isLockedVertical: false,
    isLockedHorizontal: false,
  });

  // Mise à jour visuelle immédiate (sans animation React pour perf)
  useEffect(() => {
    if (trackRef.current) {
        trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)'; 
        trackRef.current.style.transform = `translate3d(${-currentIndex * containerWidth}px, 0, 0)`;

        const article = articles[currentIndex];
        if (article) {
            markAsRead(article.id);
            if (propSetIndex) propSetIndex(currentIndex);

            // Navigation URL silencieuse si l'index change localement
            if (paramId !== article.id) {
                navigate(`${basePath}/${article.id}`, { replace: true });
            }
        }
    }
  }, [currentIndex, containerWidth, articles, markAsRead, propSetIndex, navigate, basePath, paramId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onTouchStart = (e: TouchEvent) => {
        physics.current.isDragging = true;
        physics.current.startX = e.touches[0].clientX;
        physics.current.startY = e.touches[0].clientY;
        physics.current.currentX = e.touches[0].clientX;
        physics.current.startTime = Date.now();
        physics.current.isLockedVertical = false;
        physics.current.isLockedHorizontal = false;

        if (trackRef.current) {
            trackRef.current.style.transition = 'none';
            physics.current.initialTranslate = -currentIndex * container.clientWidth;
        }
    };

    const onTouchMove = (e: TouchEvent) => {
        if (!physics.current.isDragging) return;

        const x = e.touches[0].clientX;
        const y = e.touches[0].clientY;
        const dx = x - physics.current.startX;
        const dy = y - physics.current.startY;

        if (!physics.current.isLockedHorizontal && !physics.current.isLockedVertical) {
            if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
                if (Math.abs(dx) > Math.abs(dy)) {
                    physics.current.isLockedHorizontal = true;
                } else {
                    physics.current.isLockedVertical = true;
                    physics.current.isDragging = false; 
                    return;
                }
            }
        }

        if (physics.current.isLockedHorizontal) {
            if (e.cancelable) e.preventDefault();

            physics.current.currentX = x;
            if (trackRef.current) {
                let effectiveDx = dx;
                // Résistance élastique aux bords
                if ((currentIndex === 0 && dx > 0) || (currentIndex === articles.length - 1 && dx < 0)) {
                    effectiveDx = dx * 0.3;
                }
                const pxTranslate = physics.current.initialTranslate + effectiveDx;
                trackRef.current.style.transform = `translate3d(${pxTranslate}px, 0, 0)`;
            }
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (!physics.current.isDragging || !physics.current.isLockedHorizontal) {
            physics.current.isDragging = false;
            return;
        }

        const dx = physics.current.currentX - physics.current.startX;
        const dt = Date.now() - physics.current.startTime;
        const width = container.clientWidth;

        const isQuickSwipe = dt < 300 && Math.abs(dx) > 50;
        const isLongSwipe = Math.abs(dx) > width * 0.4;

        let newIndex = currentIndex;

        if ((isQuickSwipe || isLongSwipe)) {
            if (dx < 0 && currentIndex < articles.length - 1) {
                newIndex = currentIndex + 1;
            } else if (dx > 0 && currentIndex > 0) {
                newIndex = currentIndex - 1;
            }
        }

        if (trackRef.current) {
            trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
            trackRef.current.style.transform = `translate3d(${-newIndex * width}px, 0, 0)`;
        }

        if (newIndex !== currentIndex) {
            setCurrentIndex(newIndex);
        }

        physics.current.isDragging = false;
        physics.current.isLockedHorizontal = false;
    };

    container.addEventListener('touchstart', onTouchStart, { passive: true });
    container.addEventListener('touchmove', onTouchMove, { passive: false });
    container.addEventListener('touchend', onTouchEnd);
    container.addEventListener('touchcancel', onTouchEnd);

    return () => {
        container.removeEventListener('touchstart', onTouchStart);
        container.removeEventListener('touchmove', onTouchMove);
        container.removeEventListener('touchend', onTouchEnd);
        container.removeEventListener('touchcancel', onTouchEnd);
    };
  }, [currentIndex, articles.length]);

  // --- CONFIGURATEUR DE FLUX (Refonte) ---
  const FeedConfigurator = () => (
    <div className="w-full h-full flex flex-col bg-zinc-950 pb-safe relative">
        {/* Header */}
        <div className="p-6 pt-12 pb-4 bg-black border-b border-zinc-800 sticky top-0 z-10 flex items-center justify-between">
            <div>
                <h3 className="text-2xl font-[1000] uppercase text-white tracking-tighter">Votre Algorithme</h3>
                <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mt-1">
                    Cakenews ne décide pas pour vous.
                </p>
            </div>
            {articles.length > 0 && (
                <button onClick={() => setShowConfig(false)} className="p-2 bg-zinc-900 rounded-full text-white hover:bg-zinc-800 transition-colors border border-zinc-800">
                    <X className="w-6 h-6" />
                </button>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">

            {/* SECTION 1: THEMES GENERAUX */}
            <div>
                <div className="flex items-center gap-2 mb-4 text-zinc-400">
                    <Filter className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">Cœur de l'info</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    {THEME_GROUPS.GENERAL.map((cat) => (
                        <CategoryToggle 
                            key={cat} 
                            category={cat} 
                            isSelected={userInterests.includes(cat)} 
                            onToggle={toggleUserInterest} 
                            t={t} 
                        />
                    ))}
                </div>
            </div>

            {/* SECTION 2: LOISIRS */}
            <div>
                <div className="flex items-center gap-2 mb-4 text-zinc-400">
                    <Info className="w-4 h-4" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">Intérêts Personnels</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    {THEME_GROUPS.LOISIRS.map((cat) => (
                        <CategoryToggle 
                            key={cat} 
                            category={cat} 
                            isSelected={userInterests.includes(cat)} 
                            onToggle={toggleUserInterest} 
                            t={t} 
                        />
                    ))}
                </div>
            </div>

            {/* SECTION 3: CONTENU SENSIBLE (SÉCURITÉ) */}
            <div className="bg-red-900/10 border border-red-500/20 rounded-[32px] p-6">
                <div className="flex items-start gap-4 mb-6">
                    <div className="p-3 bg-red-500/20 rounded-xl text-red-500">
                        <ShieldAlert className="w-6 h-6" />
                    </div>
                    <div>
                        <h4 className="text-white font-[1000] uppercase text-sm tracking-wide">Filtres de Sensibilité</h4>
                        <p className="text-red-300/60 text-[10px] font-bold mt-1 leading-relaxed">
                            Cochez ces options uniquement si vous consentez à voir du contenu difficile ou choquant. Par défaut, CakeNews vous protège.
                        </p>
                    </div>
                </div>
                <div className="grid grid-cols-1 gap-2">
                    {THEME_GROUPS.SENSITIVE.map((cat) => (
                        <SensitiveToggle 
                            key={cat} 
                            category={cat} 
                            isSelected={userInterests.includes(cat)} 
                            onToggle={toggleUserInterest} 
                            t={t} 
                        />
                    ))}
                </div>
            </div>

            <div className="h-20"></div> {/* Spacer */}
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-black border-t border-zinc-800 absolute bottom-0 left-0 right-0 z-20">
            {articles.length > 0 ? (
                <button 
                    onClick={() => setShowConfig(false)}
                    className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl flex items-center justify-center gap-3 active:scale-95 transition-transform hover:bg-zinc-200"
                >
                    <Check className="w-4 h-4" /> Appliquer mes choix
                </button>
            ) : (
                <div className="text-center p-4">
                    <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">
                        Sélectionnez au moins une catégorie ci-dessus.
                    </p>
                </div>
            )}
        </div>
    </div>
  );

  // GESTION DU CAS VIDE (Pas d'articles filtrés)
  if (articles.length === 0) {
      return (
          <div className="w-full h-full bg-black relative z-[200]">
              <FeedConfigurator />
          </div>
      );
  }

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-black overflow-hidden relative"
      style={{ touchAction: 'pan-y' }} 
    >
      {/* BOUTON CONFIGURATION FLOTTANT (Seulement sur le flux perso) */}
      {basePath === '/feed' && (
          <div className="absolute top-4 right-4 z-50">
              <button 
                  onClick={() => setShowConfig(true)}
                  className="p-3 bg-black/50 backdrop-blur-md border border-white/10 rounded-full text-white/70 hover:text-white hover:bg-black/70 transition-all active:scale-95 shadow-lg group"
              >
                  <SlidersHorizontal className="w-5 h-5 group-hover:rotate-180 transition-transform duration-500" />
              </button>
          </div>
      )}

      {/* OVERLAY CONFIGURATION */}
      {showConfig && (
          <div className="absolute inset-0 z-[100] bg-black animate-in fade-in duration-200">
              <FeedConfigurator />
          </div>
      )}

      {/* FLUX D'ARTICLES */}
      <div 
        ref={trackRef}
        className="h-full flex will-change-transform"
        style={{ 
            width: `${articles.length * 100}%`, 
            transform: `translate3d(${-currentIndex * containerWidth}px, 0, 0)` 
        }}
      >
        {articles.map((article, index) => {
            // Optimisation : Ne rendre que l'article courant et ses voisins
            const distance = Math.abs(currentIndex - index);
            const shouldRender = distance <= 1;

            return (
                <div 
                    key={article.id}
                    className="h-full relative"
                    style={{ width: `${100 / articles.length}%` }}
                >
                    {shouldRender ? (
                        <ArticleCard 
                            article={article}
                            isActive={index === currentIndex}
                            isPreloading={index !== currentIndex}
                            onRoomEnter={onRoomEnter}
                            onUnreadCommentsChange={onUnreadCommentsChange}
                            navTarget={index === currentIndex ? navTarget : null}
                            onNavigateNext={() => {
                                if (index < articles.length - 1) setCurrentIndex(index + 1);
                            }}
                            commentTrigger={index === currentIndex ? commentTrigger : 0}
                        />
                    ) : (
                        <div className="w-full h-full bg-black" />
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

