  navTarget?: { articleId: string; commentId?: string } | null;
  commentTrigger?: number;
  basePath?: string; 
}

// Helper pour les boutons simples
const CategoryToggle = React.memo(({ 
  category, 
  isSelected, 
  onToggle, 
  t 
}: { 
  category: Category; 
  isSelected: boolean; 
  onToggle: (c: Category) => void; 
  t: (k: string, d?: string) => string; 
}) => {
  const catColor = CATEGORY_COLORS[category];

  return (
    <button
      onClick={() => onToggle(category)}
      className={`h-12 px-3 font-[1000] uppercase text-[10px] border transition-all flex items-center justify-between rounded-lg active:scale-95 ${
        isSelected 
          ? `bg-white text-black border-transparent shadow-lg scale-[1.02]` 
          : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700'
      }`}
    >
      <span className="truncate mr-2">{category}</span>
      <div className={`w-2 h-2 rounded-full flex-shrink-0 ${isSelected ? 'bg-black' : 'bg-zinc-700'}`} style={{ backgroundColor: isSelected ? catColor : undefined }}></div>
    </button>
  );
});

// Helper pour les switchs sensibles
const SensitiveToggle = React.memo(({ 
  category, 
  isSelected, 
  onToggle, 
  t 
}: { 
  category: Category; 
  isSelected: boolean; 
  onToggle: (c: Category) => void; 
  t: (k: string, d?: string) => string; 
}) => {
  return (
    <button
      onClick={() => onToggle(category)}
      className={`p-4 flex items-center justify-between rounded-xl border transition-all active:scale-[0.98] ${
          isSelected 
          ? 'bg-red-950/30 border-red-900 text-white' 
          : 'bg-black border-zinc-800 text-zinc-600 hover:border-zinc-700'
      }`}
    >
        <div className="flex items-center gap-3">
            <AlertTriangle className={`w-4 h-4 ${isSelected ? 'text-red-600' : 'opacity-20'}`} />
            <span className="font-[1000] uppercase text-[10px] tracking-widest">
                {category}
            </span>
        </div>

        <div className={`w-10 h-5 rounded-full relative transition-colors ${isSelected ? 'bg-red-600' : 'bg-zinc-800'}`}>
            <div className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full transition-transform ${isSelected ? 'translate-x-5' : ''}`}></div>
        </div>
    </button>
  );
});

const FeedView: React.FC<FeedViewProps> = ({
  articles,
  setActiveArticleIndex: propSetIndex,
  onRoomEnter,
  onUnreadCommentsChange,
  navTarget,
  commentTrigger,
  basePath = '/article'
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const navigate = useNavigate();
  const { id: paramId } = useParams();
  const { markAsRead, userInterests, toggleUserInterest } = useInteraction();
  const { t } = useTranslation();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [containerWidth, setContainerWidth] = useState(window.innerWidth);
  const [showConfig, setShowConfig] = useState(false);

  // --- SYNC URL & INDEX & FILTRES ---
  useEffect(() => {
    if (articles.length === 0) return;
    const targetIndex = articles.findIndex(a => a.id === paramId);

    if (targetIndex >= 0) {
      if (targetIndex !== currentIndex) {
        setCurrentIndex(targetIndex);
      }
    } else {
      const newTargetId = articles[0].id;
      if (paramId !== newTargetId) {
          navigate(`${basePath}/${newTargetId}`, { replace: true });
          setCurrentIndex(0);
      }
    }
  }, [paramId, articles, basePath, navigate]);

  useLayoutEffect(() => {
    const updateWidth = () => {
        if (containerRef.current) {
            setContainerWidth(containerRef.current.clientWidth);
        }
    };
    window.addEventListener('resize', updateWidth);
    updateWidth();
    return () => window.removeEventListener('resize', updateWidth);
  }, []);

  // Physique du Swipe (inchangé)
  const physics = useRef({
    isDragging: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    startTime: 0,
    initialTranslate: 0,
    isLockedVertical: false,
    isLockedHorizontal: false,
  });

  useEffect(() => {
    if (trackRef.current) {
        trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)'; 
        trackRef.current.style.transform = `translate3d(${-currentIndex * containerWidth}px, 0, 0)`;

        const article = articles[currentIndex];
        if (article) {
            markAsRead(article.id);
            if (propSetIndex) propSetIndex(currentIndex);
            if (paramId !== article.id) {
                navigate(`${basePath}/${article.id}`, { replace: true });
            }
        }
    }
  }, [currentIndex, containerWidth, articles, markAsRead, propSetIndex, navigate, basePath, paramId]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const onTouchStart = (e: TouchEvent) => {
        physics.current.isDragging = true;
        physics.current.startX = e.touches[0].clientX;
        physics.current.startY = e.touches[0].clientY;
        physics.current.currentX = e.touches[0].clientX;
        physics.current.startTime = Date.now();
        physics.current.isLockedVertical = false;
        physics.current.isLockedHorizontal = false;

        if (trackRef.current) {
            trackRef.current.style.transition = 'none';
            physics.current.initialTranslate = -currentIndex * container.clientWidth;
        }
    };

    const onTouchMove = (e: TouchEvent) => {
        if (!physics.current.isDragging) return;

        const x = e.touches[0].clientX;
        const y = e.touches[0].clientY;
        const dx = x - physics.current.startX;
        const dy = y - physics.current.startY;

        if (!physics.current.isLockedHorizontal && !physics.current.isLockedVertical) {
            if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
                if (Math.abs(dx) > Math.abs(dy)) {
                    physics.current.isLockedHorizontal = true;
                } else {
                    physics.current.isLockedVertical = true;
                    physics.current.isDragging = false; 
                    return;
                }
            }
        }

        if (physics.current.isLockedHorizontal) {
            if (e.cancelable) e.preventDefault();
            physics.current.currentX = x;
            if (trackRef.current) {
                let effectiveDx = dx;
                if ((currentIndex === 0 && dx > 0) || (currentIndex === articles.length - 1 && dx < 0)) {
                    effectiveDx = dx * 0.3;
                }
                const pxTranslate = physics.current.initialTranslate + effectiveDx;
                trackRef.current.style.transform = `translate3d(${pxTranslate}px, 0, 0)`;
            }
        }
    };

    const onTouchEnd = (e: TouchEvent) => {
        if (!physics.current.isDragging || !physics.current.isLockedHorizontal) {
            physics.current.isDragging = false;
            return;
        }

        const dx = physics.current.currentX - physics.current.startX;
        const dt = Date.now() - physics.current.startTime;
        const width = container.clientWidth;

        const isQuickSwipe = dt < 300 && Math.abs(dx) > 50;
        const isLongSwipe = Math.abs(dx) > width * 0.4;

        let newIndex = currentIndex;

        if ((isQuickSwipe || isLongSwipe)) {
            if (dx < 0 && currentIndex < articles.length - 1) {
                newIndex = currentIndex + 1;
            } else if (dx > 0 && currentIndex > 0) {
                newIndex = currentIndex - 1;
            }
        }

        if (trackRef.current) {
            trackRef.current.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
            trackRef.current.style.transform = `translate3d(${-newIndex * width}px, 0, 0)`;
        }

        if (newIndex !== currentIndex) {
            setCurrentIndex(newIndex);
        }

        physics.current.isDragging = false;
        physics.current.isLockedHorizontal = false;
    };

    container.addEventListener('touchstart', onTouchStart, { passive: true });
    container.addEventListener('touchmove', onTouchMove, { passive: false });
    container.addEventListener('touchend', onTouchEnd);
    container.addEventListener('touchcancel', onTouchEnd);

    return () => {
        container.removeEventListener('touchstart', onTouchStart);
        container.removeEventListener('touchmove', onTouchMove);
        container.removeEventListener('touchend', onTouchEnd);
        container.removeEventListener('touchcancel', onTouchEnd);
    };
  }, [currentIndex, articles.length]);

  // --- CONFIGURATEUR DE FLUX (Refonte Totale) ---
  const FeedConfigurator = () => (
    <div className="w-full h-full flex flex-col bg-zinc-950 pb-safe relative">
        {/* Header */}
        <div className="p-6 pt-12 pb-4 bg-black border-b border-zinc-800 sticky top-0 z-10 flex items-center justify-between shadow-xl">
            <div>
                <h3 className="text-2xl font-[1000] uppercase text-white tracking-tighter">Votre Algorithme</h3>
                <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mt-1">
                    Définissez vos propres règles. Zéro tabou.
                </p>
            </div>
            {articles.length > 0 && (
                <button onClick={() => setShowConfig(false)} className="p-2 bg-zinc-900 rounded-full text-white hover:bg-zinc-800 transition-colors border border-zinc-800">
                    <X className="w-6 h-6" />
                </button>
            )}
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-10">

            {/* GROUPES DYNAMIQUES (Hors Sensitive) */}
            {Object.entries(THEME_GROUPS).map(([groupKey, groupCategories]) => {
                if (groupKey === 'SENSITIVE') return null; // Traité séparément

                let Icon = Target;
                let label = groupKey;
                if (groupKey === 'ACTUALITES') Icon = Monitor;
                if (groupKey === 'FUTUR') Icon = Zap;
                if (groupKey === 'LIFESTYLE') Icon = Heart;
                if (groupKey === 'ADRENALINE') Icon = Flame;

                return (
                    <div key={groupKey}>
                        <div className="flex items-center gap-2 mb-4 text-zinc-400">
                            <Icon className="w-4 h-4" />
                            <span className="text-[10px] font-black uppercase tracking-[0.2em]">{label}</span>
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            {groupCategories.map((cat) => (
                                <CategoryToggle 
                                    key={cat} 
                                    category={cat} 
                                    isSelected={userInterests.includes(cat)} 
                                    onToggle={toggleUserInterest} 
                                    t={t} 
                                />
                            ))}
                        </div>
                    </div>
                );
            })}

            {/* SECTION ZONE ROUGE (CONTENU SENSIBLE) */}
            <div className="bg-red-950/10 border border-red-900/30 rounded-[32px] p-6 mt-8">
                <div className="flex items-start gap-4 mb-6">
                    <div className="p-3 bg-red-900/20 rounded-xl text-red-600 border border-red-900/50">
                        <ShieldAlert className="w-6 h-6" />
                    </div>
                    <div>
                        <h4 className="text-red-500 font-[1000] uppercase text-sm tracking-wide">ZONE ROUGE</h4>
                        <p className="text-red-300/40 text-[10px] font-bold mt-1 leading-relaxed">
                            Contenu brut, non censuré ou choquant. Activez ces filtres uniquement si vous acceptez de voir la réalité sans filtre.
                        </p>
                    </div>
                </div>
                <div className="grid grid-cols-1 gap-2">
                    {THEME_GROUPS.SENSITIVE.map((cat) => (
                        <SensitiveToggle 
                            key={cat} 
                            category={cat} 
                            isSelected={userInterests.includes(cat)} 
                            onToggle={toggleUserInterest} 
                            t={t} 
                        />
                    ))}
                </div>
            </div>

            <div className="h-20"></div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-black border-t border-zinc-800 absolute bottom-0 left-0 right-0 z-20">
            {articles.length > 0 ? (
                <button 
                    onClick={() => setShowConfig(false)}
                    className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl flex items-center justify-center gap-3 active:scale-95 transition-transform hover:bg-zinc-200"
                >
                    <Check className="w-4 h-4" /> Appliquer mes choix
                </button>
            ) : (
                <div className="text-center p-4">
                    <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">
                        Sélectionnez au moins une catégorie ci-dessus.
                    </p>
                </div>
            )}
        </div>
    </div>
  );

  // GESTION DU CAS VIDE (Pas d'articles filtrés)
  if (articles.length === 0) {
      return (
          <div className="w-full h-full bg-black relative z-[200]">
              <FeedConfigurator />
          </div>
      );
  }

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-black overflow-hidden relative"
      style={{ touchAction: 'pan-y' }} 
    >
      {/* BOUTON CONFIGURATION FLOTTANT */}
      {basePath === '/feed' && (
          <div className="absolute top-4 right-4 z-50">
              <button 
                  onClick={() => setShowConfig(true)}
                  className="p-3 bg-black/50 backdrop-blur-md border border-white/10 rounded-full text-white/70 hover:text-white hover:bg-black/70 transition-all active:scale-95 shadow-lg group"
              >
                  <SlidersHorizontal className="w-5 h-5 group-hover:rotate-180 transition-transform duration-500" />
              </button>
          </div>
      )}

      {/* OVERLAY CONFIGURATION */}
      {showConfig && (
          <div className="absolute inset-0 z-[100] bg-black animate-in fade-in duration-200">
              <FeedConfigurator />
          </div>
      )}

      {/* FLUX D'ARTICLES */}
      <div 
        ref={trackRef}
        className="h-full flex will-change-transform"
        style={{ 
            width: `${articles.length * 100}%`, 
            transform: `translate3d(${-currentIndex * containerWidth}px, 0, 0)` 
        }}
      >
        {articles.map((article, index) => {
            const distance = Math.abs(currentIndex - index);
            const shouldRender = distance <= 1;

            return (
                <div 
                    key={article.id}
                    className="h-full relative"
                    style={{ width: `${100 / articles.length}%` }}
                >
                    {shouldRender ? (
                        <ArticleCard 
                            article={article}
                            isActive={index === currentIndex}
                            isPreloading={index !== currentIndex}
                            onRoomEnter={onRoomEnter}
                            onUnreadCommentsChange={onUnreadCommentsChange}
                            navTarget={index === currentIndex ? navTarget : null}
                            onNavigateNext={() => {
                                if (index < articles.length - 1) setCurrentIndex(index + 1);
                            }}
                            commentTrigger={index === currentIndex ? commentTrigger : 0}
                        />
                    ) : (
                        <div className="w-full h-full bg-black" />
                    )}
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default React.memo(FeedView);

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
          return this.props.fallback;
      }
      return (
        <div className="w-full h-full flex flex-col items-center justify-center bg-black p-8 text-center">
          <AlertTriangle className="w-16 h-16 text-red-600 mb-6" />
          <h2 className="text-xl font-black uppercase text-white mb-2 tracking-tight">Signal Interrompu</h2>
          <p className="text-white/50 text-xs font-mono mb-8 uppercase">Une erreur critique est survenue dans ce module.</p>

          <button 
            onClick={() => window.location.reload()}
            className="flex items-center gap-2 px-6 py-3 bg-white text-black rounded-xl font-black uppercase text-xs tracking-widest active:scale-95 transition-transform"
          >
            <RefreshCw className="w-4 h-4" /> Relancer l'app
          </button>

          {process.env.NODE_ENV === 'development' && (
              <pre className="mt-8 p-4 bg-zinc-900 rounded-lg text-[10px] text-red-400 text-left w-full overflow-auto max-h-40">
                  {this.state.error?.toString()}
              </pre>
          )}
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { UserLocation, Category, UserStats } from '../types';

export type ArticleVibe = 'shocked' | 'skeptical' | 'bullish' | 'validated' | null;

interface InteractionContextType {
  likedIds: Set<string>;
  savedIds: Set<string>;
  readItemIds: Set<string>;
  articleVibes: Record<string, ArticleVibe>;
  userLocation: UserLocation;
  userInterests: Category[];
  userStats: UserStats;
  hasCompletedOnboarding: boolean; // NOUVEAU

  toggleLike: (id: string) => void;
  toggleSave: (id: string) => void;
  markAsRead: (id: string) => void;
  trackCommentPosted: () => void;
  setArticleVibe: (articleId: string, vibe: ArticleVibe) => void;
  updateUserLocation: (loc: Partial<UserLocation>) => void;
  toggleUserInterest: (cat: Category) => void;
  completeOnboarding: () => void; // NOUVEAU
  isRead: (id: string) => boolean;
  isLiked: (id: string) => boolean;
  isSaved: (id: string) => boolean;
  triggerHaptic: (pattern?: 'light' | 'medium' | 'heavy' | 'success') => void;
}

const InteractionContext = createContext<InteractionContextType | undefined>(undefined);

const DEFAULT_USER_LOCATION: UserLocation = {
    neighborhood: '',
    city: '',
    country: '',
    isSet: false
};

const DEFAULT_USER_STATS: UserStats = {
    likesGiven: 0,
    likesReceived: 0,
    commentsPosted: 0,
    reportsReceived: 0,
    trustScore: 50
};

// Intérêts vides par défaut pour forcer le choix
const DEFAULT_INTERESTS: Category[] = [];

export const InteractionProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [likedIds, setLikedIds] = useState<Set<string>>(() => {
    try {
      const saved = localStorage.getItem('cakenews-likes');
      return saved ? new Set(JSON.parse(saved)) : new Set();
    } catch (e) { return new Set(); }
  });

  const [savedIds, setSavedIds] = useState<Set<string>>(() => {
    try {
      const saved = localStorage.getItem('cakenews-saved');
      return saved ? new Set(JSON.parse(saved)) : new Set();
    } catch (e) { return new Set(); }
  });

  const [userStats, setUserStats] = useState<UserStats>(() => {
      try {
          const saved = localStorage.getItem('cakenews-user-stats');
          return saved ? JSON.parse(saved) : DEFAULT_USER_STATS;
      } catch { return DEFAULT_USER_STATS; }
  });

  const [userLocation, setUserLocationState] = useState<UserLocation>(() => {
      try {
          const saved = localStorage.getItem('cakenews-user-location');
          return saved ? JSON.parse(saved) : DEFAULT_USER_LOCATION;
      } catch (e) { return DEFAULT_USER_LOCATION; }
  });

  const [userInterests, setUserInterests] = useState<Category[]>(() => {
      try {
          const saved = localStorage.getItem('cakenews-user-interests');
          return saved ? JSON.parse(saved) : DEFAULT_INTERESTS;
      } catch (e) { return DEFAULT_INTERESTS; }
  });

  // Gestion Onboarding
  const [hasCompletedOnboarding, setHasCompletedOnboarding] = useState<boolean>(() => {
      return localStorage.getItem('cakenews-onboarding-complete') === 'true';
  });

  const [readItemIds, setReadItemIds] = useState<Set<string>>(new Set());
  const [articleVibes, setArticleVibes] = useState<Record<string, ArticleVibe>>({});

  useEffect(() => {
    const timer = setTimeout(() => {
      try {
        localStorage.setItem('cakenews-likes', JSON.stringify(Array.from(likedIds)));
      } catch (e) { }
    }, 1000); 
    return () => clearTimeout(timer);
  }, [likedIds]);

  useEffect(() => {
    const timer = setTimeout(() => {
      try {
        localStorage.setItem('cakenews-saved', JSON.stringify(Array.from(savedIds)));
      } catch (e) { }
    }, 1000); 
    return () => clearTimeout(timer);
  }, [savedIds]);

  useEffect(() => {
      const timer = setTimeout(() => {
          localStorage.setItem('cakenews-user-stats', JSON.stringify(userStats));
      }, 500);
      return () => clearTimeout(timer);
  }, [userStats]);

  useEffect(() => {
      localStorage.setItem('cakenews-user-location', JSON.stringify(userLocation));
  }, [userLocation]);

  useEffect(() => {
      localStorage.setItem('cakenews-user-interests', JSON.stringify(userInterests));
  }, [userInterests]);

  const triggerHaptic = useCallback((pattern: 'light' | 'medium' | 'heavy' | 'success' = 'light') => {
     if (navigator.vibrate) {
         switch(pattern) {
             case 'light': navigator.vibrate(10); break;
             case 'medium': navigator.vibrate(25); break;
             case 'heavy': navigator.vibrate([30, 50, 30]); break;
             case 'success': navigator.vibrate([10, 30, 10, 30]); break;
         }
     }
  }, []);

  const toggleLike = useCallback((id: string) => {
    setLikedIds(prev => {
      const next = new Set(prev);
      let newStats = { ...userStats };
      if (next.has(id)) {
          next.delete(id);
      } else {
          next.add(id);
          newStats.likesGiven += 1;
      }
      setUserStats(newStats);
      return next;
    });
    triggerHaptic('light');
  }, [triggerHaptic, userStats]);

  const toggleSave = useCallback((id: string) => {
    setSavedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
    triggerHaptic('success');
  }, [triggerHaptic]);

  const markAsRead = useCallback((id: string) => {
    setReadItemIds(prev => new Set(prev).add(id));
  }, []);

  const trackCommentPosted = useCallback(() => {
      setUserStats(prev => ({ ...prev, commentsPosted: prev.commentsPosted + 1 }));
  }, []);

  const setArticleVibe = useCallback((articleId: string, vibe: ArticleVibe) => {
    setArticleVibes(prev => ({ ...prev, [articleId]: vibe }));
  }, []);

  const updateUserLocation = useCallback((loc: Partial<UserLocation>) => {
      setUserLocationState(prev => ({ ...prev, ...loc, isSet: true }));
  }, []);

  const toggleUserInterest = useCallback((cat: Category) => {
      setUserInterests(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]);
  }, []);

  const completeOnboarding = useCallback(() => {
      setHasCompletedOnboarding(true);
      localStorage.setItem('cakenews-onboarding-complete', 'true');
  }, []);

  const isRead = useCallback((id: string) => readItemIds.has(id), [readItemIds]);
  const isLiked = useCallback((id: string) => likedIds.has(id), [likedIds]);
  const isSaved = useCallback((id: string) => savedIds.has(id), [savedIds]);

  return (
    <InteractionContext.Provider value={{ 
      likedIds, savedIds, readItemIds, articleVibes, userLocation, userInterests, userStats, hasCompletedOnboarding,
      toggleLike, toggleSave, markAsRead, trackCommentPosted, setArticleVibe, updateUserLocation, toggleUserInterest, completeOnboarding,
      isRead, isLiked, isSaved, triggerHaptic
    }}>
      {children}
    </InteractionContext.Provider>
  );
};

export const useInteraction = () => {
  const context = useContext(InteractionContext);
  if (!context) throw new Error('useInteraction must be used within InteractionProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { ArrowRight, Check, ShieldAlert, Target, Zap, Heart, Flame, Monitor, AlertTriangle } from 'lucide-react';
import { THEME_GROUPS, CATEGORY_COLORS } from '../../constants';
import { Category } from '../../types';
import { useInteraction } from '../../context/InteractionContext';

const OnboardingWizard: React.FC = () => {
  const { toggleUserInterest, userInterests, completeOnboarding, triggerHaptic } = useInteraction();
  const [step, setStep] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);

  // Étapes : 
  // 0: Intro
  // 1: Intérêts Généraux (Actualités + Futur)
  // 2: Lifestyle & Divertissement (Lifestyle + Divertissement + Adrénaline)
  // 3: Zone Rouge (Sensitive - Opt-in Explicite)
  // 4: Finalisation

  const handleNext = () => {
    triggerHaptic('medium');
    setIsAnimating(true);
    setTimeout(() => {
        if (step === 3 && userInterests.length === 0) {
            alert("Veuillez sélectionner au moins un intérêt pour continuer.");
            setIsAnimating(false);
            return;
        }
        setStep(prev => prev + 1);
        setIsAnimating(false);
    }, 300);
  };

  const handleFinish = () => {
      triggerHaptic('success');
      // Petit effet de chargement fictif pour "construire l'algo"
      setStep(4); 
      setTimeout(() => {
          completeOnboarding();
      }, 2000);
  };

  const ToggleButton = ({ cat }: { cat: Category }) => {
      const isSelected = userInterests.includes(cat);
      const color = CATEGORY_COLORS[cat];

      return (
          <button
            onClick={() => { triggerHaptic('light'); toggleUserInterest(cat); }}
            className={`
                relative px-4 py-3 rounded-xl border-2 transition-all duration-200 flex items-center justify-between group
                ${isSelected ? 'bg-white border-white scale-[1.02]' : 'bg-zinc-900 border-zinc-800 hover:border-zinc-700'}
            `}
          >
              <span className={`text-[11px] font-[1000] uppercase tracking-wider ${isSelected ? 'text-black' : 'text-zinc-400'}`}>
                  {cat}
              </span>
              <div 
                className={`w-3 h-3 rounded-full transition-colors ${isSelected ? 'scale-110' : 'opacity-30'}`}
                style={{ backgroundColor: isSelected ? color : '#52525b' }} 
              />
          </button>
      );
  };

  const SensitiveToggle = ({ cat }: { cat: Category }) => {
      const isSelected = userInterests.includes(cat);

      return (
          <button
            onClick={() => { triggerHaptic('medium'); toggleUserInterest(cat); }}
            className={`
                w-full p-5 rounded-2xl border-2 transition-all duration-200 flex items-center justify-between
                ${isSelected 
                    ? 'bg-red-600 border-red-500 shadow-[0_0_20px_rgba(220,38,38,0.4)]' 
                    : 'bg-black border-zinc-800 hover:bg-zinc-900'
                }
            `}
          >
              <div className="flex items-center gap-4">
                  <div className={`p-2 rounded-lg ${isSelected ? 'bg-black/20' : 'bg-zinc-800'}`}>
                      <AlertTriangle className={`w-5 h-5 ${isSelected ? 'text-white' : 'text-zinc-600'}`} />
                  </div>
                  <div className="text-left">
                      <span className={`text-xs font-[1000] uppercase tracking-widest block ${isSelected ? 'text-white' : 'text-zinc-500'}`}>
                          {cat}
                      </span>
                  </div>
              </div>

              <div className={`w-12 h-7 rounded-full p-1 transition-colors ${isSelected ? 'bg-black/30' : 'bg-zinc-800'}`}>
                  <div className={`w-5 h-5 bg-white rounded-full shadow-md transition-transform duration-300 ${isSelected ? 'translate-x-5' : ''}`} />
              </div>
          </button>
      );
  };

  // --- RENDU DES ÉTAPES ---

  if (step === 0) {
      return (
          <div className="fixed inset-0 bg-black z-[1000] flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
              <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-8 shadow-[0_0_40px_rgba(255,255,255,0.2)]">
                  <Target className="w-12 h-12 text-black" />
              </div>
              <h1 className="text-4xl font-[1000] uppercase text-white mb-4 tracking-tighter leading-[0.9]">
                  CAKENEWS<br/><span className="text-zinc-600">SETUP</span>
              </h1>
              <p className="text-zinc-400 text-sm font-medium leading-relaxed max-w-xs mb-12">
                  L'information ne doit pas être subie.<br/>
                  Construisez votre propre algorithme éditorial en 3 étapes simples.
              </p>
              <button 
                onClick={handleNext}
                className="w-full max-w-xs py-5 bg-white text-black rounded-[20px] font-black uppercase text-sm tracking-[0.2em] flex items-center justify-center gap-3 active:scale-95 transition-transform"
              >
                  COMMENCER <ArrowRight className="w-5 h-5" />
              </button>
          </div>
      );
  }

  if (step === 1) {
      return (
          <div className={`fixed inset-0 bg-black z-[1000] flex flex-col p-6 transition-opacity duration-300 ${isAnimating ? 'opacity-0' : 'opacity-100'}`}>
              <div className="mt-8 mb-8">
                  <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Étape 1/3</span>
                  <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-2">Le Cœur de l'Info</h2>
                  <p className="text-zinc-500 text-xs mt-2">Sélectionnez les piliers fondamentaux de votre veille.</p>
              </div>

              <div className="flex-1 overflow-y-auto space-y-8 pb-32">
                  <div>
                      <div className="flex items-center gap-2 mb-4 text-white">
                          <Monitor className="w-4 h-4" />
                          <span className="text-xs font-black uppercase tracking-widest">ACTUALITÉS</span>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                          {THEME_GROUPS.ACTUALITES.map(cat => <ToggleButton key={cat} cat={cat} />)}
                      </div>
                  </div>

                  <div>
                      <div className="flex items-center gap-2 mb-4 text-cyan-400">
                          <Zap className="w-4 h-4" />
                          <span className="text-xs font-black uppercase tracking-widest">FUTUR & TECH</span>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                          {THEME_GROUPS.FUTUR.map(cat => <ToggleButton key={cat} cat={cat} />)}
                      </div>
                  </div>
              </div>

              <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black to-transparent">
                  <button onClick={handleNext} className="w-full py-5 bg-zinc-800 hover:bg-white hover:text-black text-white rounded-[20px] font-black uppercase text-sm tracking-[0.2em] transition-all">
                      CONTINUER
                  </button>
              </div>
          </div>
      );
  }

  if (step === 2) {
      return (
          <div className={`fixed inset-0 bg-black z-[1000] flex flex-col p-6 transition-opacity duration-300 ${isAnimating ? 'opacity-0' : 'opacity-100'}`}>
              <div className="mt-8 mb-8">
                  <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Étape 2/3</span>
                  <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-2">Passions & Hype</h2>
                  <p className="text-zinc-500 text-xs mt-2">Ce qui vous fait vibrer au quotidien.</p>
              </div>

              <div className="flex-1 overflow-y-auto space-y-8 pb-32">
                  <div>
                      <div className="flex items-center gap-2 mb-4 text-pink-500">
                          <Heart className="w-4 h-4" />
                          <span className="text-xs font-black uppercase tracking-widest">LIFESTYLE</span>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                          {THEME_GROUPS.LIFESTYLE.map(cat => <ToggleButton key={cat} cat={cat} />)}
                          {THEME_GROUPS.DIVERTISSEMENT.map(cat => <ToggleButton key={cat} cat={cat} />)}
                      </div>
                  </div>

                  <div>
                      <div className="flex items-center gap-2 mb-4 text-orange-500">
                          <Flame className="w-4 h-4" />
                          <span className="text-xs font-black uppercase tracking-widest">ADRÉNALINE</span>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                          {THEME_GROUPS.ADRENALINE.map(cat => <ToggleButton key={cat} cat={cat} />)}
                      </div>
                  </div>
              </div>

              <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black to-transparent">
                  <button onClick={handleNext} className="w-full py-5 bg-zinc-800 hover:bg-white hover:text-black text-white rounded-[20px] font-black uppercase text-sm tracking-[0.2em] transition-all">
                      SUIVANT
                  </button>
              </div>
          </div>
      );
  }

  if (step === 3) {
      return (
          <div className={`fixed inset-0 bg-black z-[1000] flex flex-col p-6 transition-opacity duration-300 ${isAnimating ? 'opacity-0' : 'opacity-100'}`}>
              <div className="mt-8 mb-8 border-l-4 border-red-600 pl-6 ml-1">
                  <span className="text-[10px] font-black text-red-600 uppercase tracking-widest">Zone Rouge • Sécurité</span>
                  <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-2">La Réalité Brute</h2>
                  <p className="text-zinc-400 text-xs mt-4 leading-relaxed font-medium">
                      Ces catégories contiennent des images ou récits pouvant heurter la sensibilité.
                      <br/><span className="text-white font-bold">Par défaut, elles sont masquées.</span> Activez-les uniquement si vous y consentez.
                  </p>
              </div>

              <div className="flex-1 overflow-y-auto space-y-4 pb-32">
                  {THEME_GROUPS.SENSITIVE.map(cat => <SensitiveToggle key={cat} cat={cat} />)}
              </div>

              <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black to-transparent">
                  <button 
                    onClick={handleFinish}
                    className="w-full py-5 bg-white text-black rounded-[20px] font-black uppercase text-sm tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-emerald-400 transition-colors shadow-[0_0_30px_rgba(255,255,255,0.2)]"
                  >
                      VALIDER MON FLUX <Check className="w-5 h-5" />
                  </button>
              </div>
          </div>
      );
  }

  if (step === 4) {
      return (
          <div className="fixed inset-0 bg-black z-[1000] flex flex-col items-center justify-center p-8 text-center animate-in zoom-in duration-500">
              <div className="w-16 h-16 border-4 border-white border-t-transparent rounded-full animate-spin mb-8" />
              <h2 className="text-2xl font-[1000] text-white uppercase tracking-tighter mb-2">Configuration...</h2>
              <p className="text-zinc-500 text-xs font-mono uppercase tracking-widest">
                  Compilation de vos sources<br/>
                  Ajustement des filtres<br/>
                  Synchronisation réseau
              </p>
          </div>
      );
  }

  return null;
};

export default OnboardingWizard;

import React, { useState, useCallback, useMemo, useEffect, Suspense, lazy } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation, Navigate } from 'react-router-dom';
import { AppTab, Category, Message, AppViewMode, Article } from './types';
import { CAKENEWS_MESSAGES } from './data/mockData';
import { DataService } from './services/dataService';
import { CATEGORY_COLORS } from './constants';
import BottomNav from './components/BottomNav';
import ActionBar from './components/ActionBar';
import GlobalModalRegistry from './components/GlobalModalRegistry';
import { InteractionProvider, useInteraction } from './context/InteractionContext';
import { ModalProvider, useModal } from './context/ModalContext';
import { BroadcastProvider } from './context/BroadcastContext';
import { TranslationProvider } from './context/TranslationContext';
import { ToastProvider, useToast } from './context/ToastContext';
import { ModuleLoader } from './components/ui/Loader';
import VibeTicker from './components/ui/VibeTicker';
import BreakingNewsOverlay from './components/ui/BreakingNewsOverlay';
import AuthView from './components/AuthView';
import ErrorBoundary from './components/ui/ErrorBoundary';
import OnboardingWizard from './components/onboarding/OnboardingWizard'; // IMPORT NOUVEAU
import { ChevronLeft } from 'lucide-react';

// Lazy loading
const FeedView = lazy(() => import('./components/FeedView'));
const MessagesView = lazy(() => import('./components/MessagesView'));
const ProfileView = lazy(() => import('./components/ProfileView'));
const AdminView = lazy(() => import('./components/admin/AdminView'));

const GlobalSideSignature = () => (
  <div className="fixed right-0 top-[50vw] -translate-y-1/2 z-[100] pointer-events-none select-none">
    <div className="bg-black/80 border-y border-l border-white/10 py-3 px-1.5 rounded-l-lg flex flex-col items-center transition-all duration-700">
      <span className="text-[5px] font-[1000] uppercase tracking-[0.4em] text-white vertical-text-signature whitespace-nowrap">
        CAKENEWS
      </span>
    </div>
  </div>
);

const TabLoader = () => (
  <div className="w-full h-full flex items-center justify-center bg-black animate-pulse">
    <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
  </div>
);

// Wrapper pour la logique d'état principale
const MainLayout: React.FC<{ 
    viewMode: AppViewMode, 
    allArticles: Article[],
    isLoading: boolean,
    cnMessages: Message[],
    hasNewNotification: boolean,
    setViewMode: (mode: AppViewMode) => void,
    handleLogout: () => void,
    setCnMessages: React.Dispatch<React.SetStateAction<Message[]>>,
    setHasNewNotification: React.Dispatch<React.SetStateAction<boolean>>,
}> = ({ viewMode, allArticles, isLoading, cnMessages, hasNewNotification, setViewMode, handleLogout, setCnMessages, setHasNewNotification }) => {

    const navigate = useNavigate();
    const location = useLocation();
    const { toggleLike, isLiked, toggleSave, isSaved, userInterests, toggleUserInterest, hasCompletedOnboarding } = useInteraction();
    const { openModal } = useModal();
    const { showToast } = useToast();

    const [commentTrigger, setCommentTrigger] = useState(0);
    const [isCommentBlinking, setIsCommentBlinking] = useState(false);
    const [unreadCommentsCount, setUnreadCommentsCount] = useState(0);

    // FILTRES : Basé sur les préférences utilisateur (userInterests)
    const feedArticles = useMemo(() => {
        if (!userInterests || userInterests.length === 0) return [];
        return allArticles.filter(a => userInterests.includes(a.category));
    }, [allArticles, userInterests]);

    // --- LOGIQUE MÉMOIRE DE LECTURE ---
    const [lastViewedArticleId, setLastViewedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (location.pathname.startsWith('/article/')) {
            const id = location.pathname.split('/')[2];
            setLastViewedArticleId(id);
        } else if (location.pathname === '/') {
            if (allArticles.length > 0) setLastViewedArticleId(allArticles[0].id);
        }
    }, [location.pathname, allArticles]);

    const handleHomeNavigation = useCallback(() => {
        const isCurrentlyOnFeed = location.pathname === '/' || location.pathname.startsWith('/article/');

        if (!isCurrentlyOnFeed) {
            if (lastViewedArticleId) {
                navigate(`/article/${lastViewedArticleId}`);
            } else {
                navigate('/');
            }
        } else {
            if (allArticles.length > 0) {
                navigate(`/article/${allArticles[0].id}`);
            }
        }
    }, [location.pathname, lastViewedArticleId, navigate, allArticles]);

    const currentArticleId = useMemo(() => {
        const parts = location.pathname.split('/');
        if (parts.length >= 3 && (parts[1] === 'article' || parts[1] === 'feed')) {
            return parts[2];
        }
        if (location.pathname === '/') {
            return allArticles[0]?.id;
        }
        return null;
    }, [location.pathname, allArticles]);

    const currentArticle = useMemo(() => {
        return allArticles.find(a => a.id === currentArticleId) || allArticles[0];
    }, [currentArticleId, allArticles]);

    const handleLike = useCallback(() => {
        if (!currentArticle) return;
        const isAddingLike = !isLiked(currentArticle.id);
        toggleLike(currentArticle.id);
    }, [currentArticle, isLiked, toggleLike]);

    const handleSaveAction = useCallback(() => {
        if (!currentArticle) return;
        toggleSave(currentArticle.id);
        if (!isSaved(currentArticle.id)) {
            showToast("Dossier sauvegardé", "success");
        } else {
            showToast("Retiré des favoris", "info");
        }
    }, [currentArticle, isSaved, toggleSave, showToast]);

    const handleShare = useCallback(() => {
        if (!currentArticle) return;
        openModal('SHARE', { article: currentArticle });
    }, [currentArticle, openModal]);

    const handleReportSubmitted = useCallback((ticketId: string, articleTitle: string) => {
        showToast(`Audit #${ticketId} transmis`, 'success');
        setCnMessages(prev => [{
            id: Date.now().toString(),
            sender: 'Audit CakeNews',
            avatar: 'https://picsum.photos/seed/audit/150/150',
            text: `AUDIT REÇU - Réf: ${ticketId}. Signalement pour "${articleTitle}" en cours d'analyse.`,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            isOfficial: true,
            articleId: currentArticle?.id
        }, ...prev]);
        setHasNewNotification(true);
    }, [currentArticle, setCnMessages, setHasNewNotification, showToast]);

    const handleNavigateToArticle = (id: string) => navigate(`/article/${id}`);

    const isFeedActive = location.pathname === '/' || location.pathname.startsWith('/article/') || location.pathname.startsWith('/feed');
    const accentColor = currentArticle ? (currentArticle.isExclusive ? '#ff0000' : currentArticle.isSensitive ? '#ffcc00' : CATEGORY_COLORS[currentArticle.category]) : '#ffffff';

    if (isLoading) {
        return <ModuleLoader />;
    }

    return (
        <div className="h-screen w-full bg-black text-white relative overflow-hidden flex flex-col">
            {/* ONBOARDING WIZARD BLOCKER */}
            {!hasCompletedOnboarding && viewMode !== 'ADMIN' && (
                <OnboardingWizard />
            )}

            <GlobalSideSignature />
            <BreakingNewsOverlay onNavigate={handleNavigateToArticle} />

            {isFeedActive && (
                <div className="absolute top-0 left-0 right-0 z-[60]">
                    <VibeTicker />
                </div>
            )}

            <main className="flex-1 w-full overflow-hidden relative">
                <ErrorBoundary>
                    <Suspense fallback={<TabLoader />}>
                        <Routes>
                            {/* HOME FEED (GLOBAL) */}
                            <Route path="/" element={
                                <FeedView 
                                    articles={allArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />
                            <Route path="/article/:id" element={
                                <FeedView 
                                    articles={allArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />

                            {/* CUSTOM FEED (User Preferences) */}
                            <Route path="/feed" element={
                                <FeedView 
                                    articles={feedArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />
                            <Route path="/feed/:id" element={
                                <FeedView 
                                    articles={feedArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />

                            <Route path="/messages" element={
                                <MessagesView dynamicCakeNewsMessages={cnMessages} onNavigateToArticle={handleNavigateToArticle} />
                            } />
                            <Route path="/profile" element={
                                <ProfileView 
                                    preferences={userInterests} 
                                    togglePreference={toggleUserInterest} 
                                    onLogout={handleLogout}
                                />
                            } />
                            <Route path="*" element={<Navigate to="/" replace />} />
                        </Routes>
                    </Suspense>
                </ErrorBoundary>
            </main>

            <footer className="w-full flex flex-col bg-black relative z-[55] select-none pointer-events-none">
                {isFeedActive && currentArticle && (
                    <div className="pointer-events-auto pb-[60px] bg-black">
                        <ActionBar 
                            likes={currentArticle.likes + (isLiked(currentArticle.id) ? 1 : 0)}
                            comments={currentArticle.comments}
                            isLiked={isLiked(currentArticle.id)}
                            isSaved={isSaved(currentArticle.id)}
                            isCommentBlinking={isCommentBlinking}
                            hasUnreadComments={unreadCommentsCount > 0}
                            accentColor={accentColor}
                            onLike={handleLike}
                            onSave={handleSaveAction}
                            onShare={handleShare}
                            onCommentClick={() => { setCommentTrigger(prev => prev + 1); setIsCommentBlinking(false); }}
                            onReportClick={() => openModal('REPORT', { articleTitle: currentArticle.title, onReportSubmitted: handleReportSubmitted })}
                        />
                    </div>
                )}
            </footer>

            <BottomNav 
                hasNotification={hasNewNotification} 
                onHomeClick={handleHomeNavigation} 
            />
            <GlobalModalRegistry />
        </div>
    );
};

const AppContent: React.FC = () => {
    const [viewMode, setViewMode] = useState<AppViewMode>('AUTH');
    const [allArticles, setAllArticles] = useState<Article[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [cnMessages, setCnMessages] = useState<Message[]>(CAKENEWS_MESSAGES);
    const [hasNewNotification, setHasNewNotification] = useState(false);
    const { showToast } = useToast();

    // CHARGEMENT INITIAL DES DONNÉES
    useEffect(() => {
        const loadArticles = async () => {
            try {
                setIsLoading(true);
                const data = await DataService.getArticles();
                setAllArticles(data);
            } catch (error) {
                console.error("Failed to fetch articles", error);
                showToast("Erreur connexion réseau", "error");
            } finally {
                setIsLoading(false);
            }
        };

        if (viewMode !== 'AUTH') {
            loadArticles();
        }
    }, [viewMode, showToast]);

    const handleArticlePublish = async (newArticle: Article) => {
        try {
            const savedArticle = await DataService.upsertArticle(newArticle);
            if (savedArticle) {
                setAllArticles(prev => {
                    const exists = prev.findIndex(a => a.id === savedArticle.id);
                    if (exists >= 0) {
                        const updated = [...prev];
                        updated[exists] = savedArticle;
                        return updated;
                    }
                    return [savedArticle, ...prev];
                });
                showToast("Article publié sur le réseau", "success");
            }
        } catch (e) {
            showToast("Échec de la publication", "error");
        }
    };

    const handleSendSystemMessage = (target: string, content: string) => {
        const newMessage: Message = {
            id: `sys-${Date.now()}`,
            sender: 'CakeNews Team',
            avatar: 'https://picsum.photos/seed/cake/150/150',
            text: target === 'ALL' ? `[BROADCAST] ${content}` : content,
            time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}),
            isOfficial: true
        };
        setCnMessages(prev => [newMessage, ...prev]);
        setHasNewNotification(true);
    };

    if (viewMode === 'AUTH') {
        return <AuthView onLogin={(role) => setViewMode(role)} />;
    }

    if (viewMode === 'ADMIN') {
        return (
            <Suspense fallback={<TabLoader />}>
                <AdminView 
                    articles={allArticles}
                    onArticlePublish={handleArticlePublish}
                    onSendSystemMessage={handleSendSystemMessage}
                    onLogout={() => setViewMode('AUTH')}
                />
            </Suspense>
        );
    }

    return (
        <Router>
            <MainLayout 
                viewMode={viewMode}
                allArticles={allArticles}
                isLoading={isLoading}
                cnMessages={cnMessages}
                hasNewNotification={hasNewNotification}
                setViewMode={setViewMode}
                handleLogout={() => setViewMode('AUTH')}
                setCnMessages={setCnMessages}
                setHasNewNotification={setHasNewNotification}
            />
        </Router>
    );
};

const App: React.FC = () => (
  <InteractionProvider>
    <BroadcastProvider>
      <TranslationProvider>
        <ModalProvider>
          <ToastProvider> 
            <AppContent />
          </ToastProvider>
        </ModalProvider>
      </TranslationProvider>
    </BroadcastProvider>
  </InteractionProvider>
);

export default App;

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  // Explicitly declare props to satisfy TS in strict environments where React.Component inheritance might be ambiguous
  public declare props: Readonly<ErrorBoundaryProps>;

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
          return this.props.fallback;
      }
      return (
        <div className="w-full h-full flex flex-col items-center justify-center bg-black p-8 text-center">
          <AlertTriangle className="w-16 h-16 text-red-600 mb-6" />
          <h2 className="text-xl font-black uppercase text-white mb-2 tracking-tight">Signal Interrompu</h2>
          <p className="text-white/50 text-xs font-mono mb-8 uppercase">Une erreur critique est survenue dans ce module.</p>

          <button 
            onClick={() => window.location.reload()}
            className="flex items-center gap-2 px-6 py-3 bg-white text-black rounded-xl font-black uppercase text-xs tracking-widest active:scale-95 transition-transform"
          >
            <RefreshCw className="w-4 h-4" /> Relancer l'app
          </button>

          {process.env.NODE_ENV === 'development' && (
              <pre className="mt-8 p-4 bg-zinc-900 rounded-lg text-[10px] text-red-400 text-left w-full overflow-auto max-h-40">
                  {this.state.error?.toString()}
              </pre>
          )}
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

