import React, { useState, useCallback, useMemo, useEffect, Suspense, lazy } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation, Navigate } from 'react-router-dom';
import { AppTab, Category, Message, AppViewMode, Article } from './types';
import { CAKENEWS_MESSAGES } from './data/mockData';
import { DataService } from './services/dataService';
import { CATEGORY_COLORS } from './constants';
import BottomNav from './components/BottomNav';
import ActionBar from './components/ActionBar';
import GlobalModalRegistry from './components/GlobalModalRegistry';
import { InteractionProvider, useInteraction } from './context/InteractionContext';
import { ModalProvider, useModal } from './context/ModalContext';
import { BroadcastProvider } from './context/BroadcastContext';
import { TranslationProvider } from './context/TranslationContext';
import { ToastProvider, useToast } from './context/ToastContext';
import { ModuleLoader } from './components/ui/Loader';
import VibeTicker from './components/ui/VibeTicker';
import BreakingNewsOverlay from './components/ui/BreakingNewsOverlay';
import AuthView from './components/AuthView';
import ErrorBoundary from './components/ui/ErrorBoundary';
import OnboardingWizard from './components/onboarding/OnboardingWizard';
import { ChevronLeft } from 'lucide-react';

// Lazy loading
const FeedView = lazy(() => import('./components/FeedView'));
const MessagesView = lazy(() => import('./components/MessagesView'));
const ProfileView = lazy(() => import('./components/ProfileView'));
const AdminView = lazy(() => import('./components/admin/AdminView'));

const GlobalSideSignature = () => (
  <div className="fixed right-0 top-[50vw] -translate-y-1/2 z-[100] pointer-events-none select-none">
    <div className="bg-black/80 border-y border-l border-white/10 py-3 px-1.5 rounded-l-lg flex flex-col items-center transition-all duration-700">
      <span className="text-[5px] font-[1000] uppercase tracking-[0.4em] text-white vertical-text-signature whitespace-nowrap">
        CAKENEWS
      </span>
    </div>
  </div>
);

const TabLoader = () => (
  <div className="w-full h-full flex items-center justify-center bg-black animate-pulse">
    <div className="w-8 h-8 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
  </div>
);

// Wrapper pour la logique d'état principale
const MainLayout: React.FC<{ 
    viewMode: AppViewMode, 
    allArticles: Article[],
    isLoading: boolean,
    cnMessages: Message[],
    hasNewNotification: boolean,
    setViewMode: (mode: AppViewMode) => void,
    handleLogout: () => void,
    setCnMessages: React.Dispatch<React.SetStateAction<Message[]>>,
    setHasNewNotification: React.Dispatch<React.SetStateAction<boolean>>,
}> = ({ viewMode, allArticles, isLoading, cnMessages, hasNewNotification, setViewMode, handleLogout, setCnMessages, setHasNewNotification }) => {

    const navigate = useNavigate();
    const location = useLocation();
    const { toggleLike, isLiked, toggleSave, isSaved, userInterests, toggleUserInterest, hasCompletedOnboarding } = useInteraction();
    const { openModal } = useModal();
    const { showToast } = useToast();

    const [commentTrigger, setCommentTrigger] = useState(0);
    const [isCommentBlinking, setIsCommentBlinking] = useState(false);
    const [unreadCommentsCount, setUnreadCommentsCount] = useState(0);

    // FILTRES STRICTS : L'application ne propose QUE ce que l'utilisateur a choisi.
    // Si userInterests est vide (ex: onboarding), on n'affiche rien ou tout (ici géré par onboarding)
    const filteredArticles = useMemo(() => {
        // Si l'admin regarde, on montre tout.
        if (viewMode === 'ADMIN') return allArticles;

        // Si l'onboarding n'est pas fini, on attend.
        if (!hasCompletedOnboarding) return [];

        // Si l'utilisateur n'a aucun intérêt (cas rare post-onboarding), on montre tout par défaut ou un message vide
        if (!userInterests || userInterests.length === 0) return allArticles; 

        return allArticles.filter(a => userInterests.includes(a.category));
    }, [allArticles, userInterests, hasCompletedOnboarding, viewMode]);

    // --- LOGIQUE MÉMOIRE DE LECTURE ---
    const [lastViewedArticleId, setLastViewedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (location.pathname.startsWith('/article/')) {
            const id = location.pathname.split('/')[2];
            setLastViewedArticleId(id);
        } else if (location.pathname === '/') {
            if (filteredArticles.length > 0) setLastViewedArticleId(filteredArticles[0].id);
        }
    }, [location.pathname, filteredArticles]);

    const handleHomeNavigation = useCallback(() => {
        const isCurrentlyOnFeed = location.pathname === '/' || location.pathname.startsWith('/article/');

        if (!isCurrentlyOnFeed) {
            if (lastViewedArticleId) {
                navigate(`/article/${lastViewedArticleId}`);
            } else {
                navigate('/');
            }
        } else {
            if (filteredArticles.length > 0) {
                navigate(`/article/${filteredArticles[0].id}`);
            }
        }
    }, [location.pathname, lastViewedArticleId, navigate, filteredArticles]);

    const currentArticleId = useMemo(() => {
        const parts = location.pathname.split('/');
        if (parts.length >= 3 && (parts[1] === 'article' || parts[1] === 'feed')) {
            return parts[2];
        }
        if (location.pathname === '/') {
            return filteredArticles[0]?.id;
        }
        return null;
    }, [location.pathname, filteredArticles]);

    const currentArticle = useMemo(() => {
        return filteredArticles.find(a => a.id === currentArticleId) || filteredArticles[0];
    }, [currentArticleId, filteredArticles]);

    const handleLike = useCallback(() => {
        if (!currentArticle) return;
        const isAddingLike = !isLiked(currentArticle.id);
        toggleLike(currentArticle.id);
    }, [currentArticle, isLiked, toggleLike]);

    const handleSaveAction = useCallback(() => {
        if (!currentArticle) return;
        toggleSave(currentArticle.id);
        if (!isSaved(currentArticle.id)) {
            showToast("Dossier sauvegardé", "success");
        } else {
            showToast("Retiré des favoris", "info");
        }
    }, [currentArticle, isSaved, toggleSave, showToast]);

    const handleShare = useCallback(() => {
        if (!currentArticle) return;
        openModal('SHARE', { article: currentArticle });
    }, [currentArticle, openModal]);

    const handleReportSubmitted = useCallback((ticketId: string, articleTitle: string) => {
        showToast(`Audit #${ticketId} transmis`, 'success');
        setCnMessages(prev => [{
            id: Date.now().toString(),
            sender: 'Audit CakeNews',
            avatar: 'https://picsum.photos/seed/audit/150/150',
            text: `AUDIT REÇU - Réf: ${ticketId}. Signalement pour "${articleTitle}" en cours d'analyse.`,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            isOfficial: true,
            articleId: currentArticle?.id
        }, ...prev]);
        setHasNewNotification(true);
    }, [currentArticle, setCnMessages, setHasNewNotification, showToast]);

    const handleNavigateToArticle = (id: string) => navigate(`/article/${id}`);

    const isFeedActive = location.pathname === '/' || location.pathname.startsWith('/article/') || location.pathname.startsWith('/feed');
    const accentColor = currentArticle ? (currentArticle.isExclusive ? '#ff0000' : currentArticle.isSensitive ? '#ffcc00' : CATEGORY_COLORS[currentArticle.category]) : '#ffffff';

    if (isLoading) {
        return <ModuleLoader />;
    }

    return (
        <div className="h-screen w-full bg-black text-white relative overflow-hidden flex flex-col">
            {/* L'ARCHITECTE (ONBOARDING) BLOQUE TOUT TANT QUE PAS FINI */}
            {!hasCompletedOnboarding && viewMode !== 'ADMIN' && (
                <OnboardingWizard />
            )}

            <GlobalSideSignature />
            <BreakingNewsOverlay onNavigate={handleNavigateToArticle} />

            {isFeedActive && (
                <div className="absolute top-0 left-0 right-0 z-[60]">
                    <VibeTicker />
                </div>
            )}

            <main className="flex-1 w-full overflow-hidden relative">
                <ErrorBoundary>
                    <Suspense fallback={<TabLoader />}>
                        <Routes>
                            {/* HOME FEED (Maintenant FILTRÉ par les préférences) */}
                            <Route path="/" element={
                                <FeedView 
                                    articles={filteredArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />
                            <Route path="/article/:id" element={
                                <FeedView 
                                    articles={filteredArticles} 
                                    onRoomEnter={() => { setIsCommentBlinking(true); setTimeout(() => setIsCommentBlinking(false), 4000); }}
                                    onUnreadCommentsChange={setUnreadCommentsCount}
                                    commentTrigger={commentTrigger}
                                    basePath="/article"
                                />
                            } />

                            {/* LE FLUX SECONDAIRE DEVIENT REDONDANT SI LA HOME EST FILTRÉE */}
                            {/* On le garde pour compatibilité mais il affiche la même chose */}
                            <Route path="/feed" element={
                                <FeedView 
                                    articles={filteredArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />
                            <Route path="/feed/:id" element={
                                <FeedView 
                                    articles={filteredArticles} 
                                    onRoomEnter={() => {}}
                                    basePath="/feed"
                                />
                            } />

                            <Route path="/messages" element={
                                <MessagesView dynamicCakeNewsMessages={cnMessages} onNavigateToArticle={handleNavigateToArticle} />
                            } />
                            <Route path="/profile" element={
                                <ProfileView 
                                    preferences={userInterests} 
                                    togglePreference={toggleUserInterest} 
                                    onLogout={handleLogout}
                                />
                            } />
                            <Route path="*" element={<Navigate to="/" replace />} />
                        </Routes>
                    </Suspense>
                </ErrorBoundary>
            </main>

            <footer className="w-full flex flex-col bg-black relative z-[55] select-none pointer-events-none">
                {isFeedActive && currentArticle && (
                    <div className="pointer-events-auto pb-[60px] bg-black">
                        <ActionBar 
                            likes={currentArticle.likes + (isLiked(currentArticle.id) ? 1 : 0)}
                            comments={currentArticle.comments}
                            isLiked={isLiked(currentArticle.id)}
                            isSaved={isSaved(currentArticle.id)}
                            isCommentBlinking={isCommentBlinking}
                            hasUnreadComments={unreadCommentsCount > 0}
                            accentColor={accentColor}
                            onLike={handleLike}
                            onSave={handleSaveAction}
                            onShare={handleShare}
                            onCommentClick={() => { setCommentTrigger(prev => prev + 1); setIsCommentBlinking(false); }}
                            onReportClick={() => openModal('REPORT', { articleTitle: currentArticle.title, onReportSubmitted: handleReportSubmitted })}
                        />
                    </div>
                )}
            </footer>

            <BottomNav 
                hasNotification={hasNewNotification} 
                onHomeClick={handleHomeNavigation} 
            />
            <GlobalModalRegistry />
        </div>
    );
};

const AppContent: React.FC = () => {
    const [viewMode, setViewMode] = useState<AppViewMode>('AUTH');
    const [allArticles, setAllArticles] = useState<Article[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [cnMessages, setCnMessages] = useState<Message[]>(CAKENEWS_MESSAGES);
    const [hasNewNotification, setHasNewNotification] = useState(false);
    const { showToast } = useToast();

    // CHARGEMENT INITIAL DES DONNÉES
    useEffect(() => {
        const loadArticles = async () => {
            try {
                setIsLoading(true);
                const data = await DataService.getArticles();
                setAllArticles(data);
            } catch (error) {
                console.error("Failed to fetch articles", error);
                showToast("Erreur connexion réseau", "error");
            } finally {
                setIsLoading(false);
            }
        };

        if (viewMode !== 'AUTH') {
            loadArticles();
        }
    }, [viewMode, showToast]);

    const handleArticlePublish = async (newArticle: Article) => {
        try {
            const savedArticle = await DataService.upsertArticle(newArticle);
            if (savedArticle) {
                setAllArticles(prev => {
                    const exists = prev.findIndex(a => a.id === savedArticle.id);
                    if (exists >= 0) {
                        const updated = [...prev];
                        updated[exists] = savedArticle;
                        return updated;
                    }
                    return [savedArticle, ...prev];
                });
                showToast("Article publié sur le réseau", "success");
            }
        } catch (e) {
            showToast("Échec de la publication", "error");
        }
    };

    const handleSendSystemMessage = (target: string, content: string) => {
        const newMessage: Message = {
            id: `sys-${Date.now()}`,
            sender: 'CakeNews Team',
            avatar: 'https://picsum.photos/seed/cake/150/150',
            text: target === 'ALL' ? `[BROADCAST] ${content}` : content,
            time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}),
            isOfficial: true
        };
        setCnMessages(prev => [newMessage, ...prev]);
        setHasNewNotification(true);
    };

    if (viewMode === 'AUTH') {
        return <AuthView onLogin={(role) => setViewMode(role)} />;
    }

    if (viewMode === 'ADMIN') {
        return (
            <Suspense fallback={<TabLoader />}>
                <AdminView 
                    articles={allArticles}
                    onArticlePublish={handleArticlePublish}
                    onSendSystemMessage={handleSendSystemMessage}
                    onLogout={() => setViewMode('AUTH')}
                />
            </Suspense>
        );
    }

    return (
        <Router>
            <MainLayout 
                viewMode={viewMode}
                allArticles={allArticles}
                isLoading={isLoading}
                cnMessages={cnMessages}
                hasNewNotification={hasNewNotification}
                setViewMode={setViewMode}
                handleLogout={() => setViewMode('AUTH')}
                setCnMessages={setCnMessages}
                setHasNewNotification={setHasNewNotification}
            />
        </Router>
    );
};

const App: React.FC = () => (
  <InteractionProvider>
    <BroadcastProvider>
      <TranslationProvider>
        <ModalProvider>
          <ToastProvider> 
            <AppContent />
          </ToastProvider>
        </ModalProvider>
      </TranslationProvider>
    </BroadcastProvider>
  </InteractionProvider>
);

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowRight, Check, ShieldAlert, Target, Zap, Heart, Flame, Monitor, AlertTriangle, Fingerprint, Sparkles } from 'lucide-react';
import { THEME_GROUPS, CATEGORY_COLORS } from '../../constants';
import { Category } from '../../types';
import { useInteraction } from '../../context/InteractionContext';

const OnboardingWizard: React.FC = () => {
  const { toggleUserInterest, userInterests, completeOnboarding, triggerHaptic } = useInteraction();
  const [step, setStep] = useState(0);
  const [isExiting, setIsExiting] = useState(false);

  // Étapes Mimo : 
  // 0: Intro (Bonjour)
  // 1: Info Sérieuse (Actualités & Tech)
  // 2: Détente (Lifestyle & Sport)
  // 3: Filtre Sensible (Zone Rouge)
  // 4: Fin

  const handleNext = () => {
    triggerHaptic('medium');

    // Validation minimale à l'étape 3 (Zone Rouge est la dernière étape de choix)
    if (step === 3 && userInterests.length === 0) {
        alert("Mimo a besoin d'au moins un sujet pour démarrer. Choisis une catégorie.");
        return;
    }

    setStep(prev => prev + 1);
  };

  const handleFinish = () => {
      triggerHaptic('success');
      setIsExiting(true); // Animation de sortie
      setTimeout(() => {
          completeOnboarding();
      }, 1500); 
  };

  // Composant Bouton QCM
  const InterestButton: React.FC<{ cat: Category }> = ({ cat }) => {
      const isSelected = userInterests.includes(cat);
      const color = CATEGORY_COLORS[cat];

      return (
          <button
            onClick={() => { triggerHaptic('light'); toggleUserInterest(cat); }}
            className={`
                relative w-full py-4 px-5 rounded-2xl border transition-all duration-200 flex items-center justify-between group
                ${isSelected 
                    ? 'bg-white border-white scale-[1.02] shadow-[0_0_20px_rgba(255,255,255,0.2)]' 
                    : 'bg-zinc-900 border-zinc-800 hover:border-zinc-700'
                }
            `}
          >
              <span className={`text-xs font-[1000] uppercase tracking-widest ${isSelected ? 'text-black' : 'text-zinc-400'}`}>
                  {cat}
              </span>
              <div 
                className={`w-3 h-3 rounded-full transition-all duration-300 ${isSelected ? 'scale-125' : 'opacity-20 scale-75'}`}
                style={{ backgroundColor: isSelected ? color : '#ffffff' }} 
              />
          </button>
      );
  };

  // Composant Zone Rouge (Design Agressif)
  const DangerToggle: React.FC<{ cat: Category }> = ({ cat }) => {
      const isSelected = userInterests.includes(cat);

      return (
          <button
            onClick={() => { triggerHaptic('medium'); toggleUserInterest(cat); }}
            className={`
                w-full p-5 rounded-xl border-l-4 transition-all duration-200 flex items-center justify-between mb-3
                ${isSelected 
                    ? 'bg-red-900/20 border-l-red-500 border-t border-r border-b border-red-500/30' 
                    : 'bg-black border-l-zinc-800 border-t border-r border-b border-zinc-900'
                }
            `}
          >
              <div className="flex items-center gap-3">
                  {isSelected && <AlertTriangle className="w-4 h-4 text-red-500 animate-pulse" />}
                  <span className={`text-[10px] font-black uppercase tracking-[0.2em] ${isSelected ? 'text-red-500' : 'text-zinc-600'}`}>
                      {cat}
                  </span>
              </div>

              <div className={`w-10 h-1 transition-all ${isSelected ? 'bg-red-500 w-16' : 'bg-zinc-800'}`} />
          </button>
      );
  };

  // --- RENDU DES ÉTAPES ---

  if (isExiting) {
      return (
          <div className="fixed inset-0 bg-black z-[1000] flex flex-col items-center justify-center font-sans">
              <div className="text-center space-y-6 animate-pulse">
                  <Fingerprint className="w-24 h-24 text-white mx-auto" strokeWidth={1} />
                  <div>
                      <h2 className="text-3xl font-[1000] uppercase text-white tracking-tighter leading-none mb-2">IDENTITÉ<br/>CONFIRMÉE</h2>
                      <p className="text-[10px] font-mono text-emerald-500 uppercase tracking-widest">Génération du flux...</p>
                  </div>
              </div>
          </div>
      );
  }

  return (
    <div className="fixed inset-0 bg-black z-[1000] flex flex-col font-sans">
        {/* Header Mimo */}
        <div className="pt-12 px-6 pb-4 border-b border-white/5 bg-black flex justify-between items-end">
            <div className="flex flex-col">
                <span className="text-[9px] font-mono text-emerald-500 mb-1 flex items-center gap-2">
                    <Sparkles className="w-3 h-3" /> ASSISTANT MIMO
                </span>
                <div className="h-1 w-24 bg-zinc-900 rounded-full overflow-hidden">
                    <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${(step / 4) * 100}%` }} />
                </div>
            </div>
            <span className="text-[10px] font-black text-white/20 uppercase tracking-widest">ÉTAPE 0{step} / 04</span>
        </div>

        {/* Contenu Scrollable */}
        <div className="flex-1 overflow-y-auto px-6 py-8">

            {step === 0 && (
                <div className="h-full flex flex-col justify-center animate-in fade-in slide-in-from-bottom-4 duration-700">
                    <div className="mb-12">
                        <h1 className="text-4xl md:text-5xl font-[1000] uppercase text-white tracking-tighter leading-[0.9] mb-6">
                            CONFIGURONS<br/><span className="text-zinc-600">TON FLUX.</span>
                        </h1>
                        <p className="text-zinc-400 text-sm font-medium leading-relaxed max-w-xs border-l-2 border-white/20 pl-4">
                            Salut, je suis Mimo. <br/><br/>
                            Pour t'éviter le contenu inutile, je dois savoir ce que tu aimes vraiment. Ça prend 30 secondes.
                        </p>
                    </div>
                </div>
            )}

            {step === 1 && (
                <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-8">
                    <div className="mb-8">
                        <span className="text-[10px] font-bold text-sky-500 uppercase tracking-widest bg-sky-500/10 px-2 py-1 rounded">Question 1/3</span>
                        <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-4 leading-none">
                            Quels sujets<br/>veux-tu suivre ?
                        </h2>
                    </div>

                    <div className="space-y-6">
                        <div>
                            <div className="flex items-center gap-2 mb-3 opacity-50">
                                <Monitor className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Société & Monde</span>
                            </div>
                            <div className="grid gap-3">
                                {THEME_GROUPS.ACTUALITES.map(cat => <InterestButton key={cat} cat={cat} />)}
                            </div>
                        </div>

                        <div>
                            <div className="flex items-center gap-2 mb-3 opacity-50">
                                <Zap className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Innovation & Futur</span>
                            </div>
                            <div className="grid gap-3">
                                {THEME_GROUPS.FUTUR.map(cat => <InterestButton key={cat} cat={cat} />)}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {step === 2 && (
                <div className="animate-in fade-in slide-in-from-bottom-8 duration-500 space-y-8">
                    <div className="mb-8">
                        <span className="text-[10px] font-bold text-pink-500 uppercase tracking-widest bg-pink-500/10 px-2 py-1 rounded">Question 2/3</span>
                        <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-4 leading-none">
                            Et pour<br/>tes loisirs ?
                        </h2>
                    </div>

                    <div className="space-y-6">
                        <div>
                            <div className="flex items-center gap-2 mb-3 opacity-50">
                                <Heart className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Culture & Lifestyle</span>
                            </div>
                            <div className="grid gap-3">
                                {[...THEME_GROUPS.LIFESTYLE, ...THEME_GROUPS.DIVERTISSEMENT].map(cat => <InterestButton key={cat} cat={cat} />)}
                            </div>
                        </div>

                        <div>
                            <div className="flex items-center gap-2 mb-3 opacity-50">
                                <Flame className="w-4 h-4" />
                                <span className="text-[9px] font-black uppercase tracking-widest">Sport & Compétition</span>
                            </div>
                            <div className="grid gap-3">
                                {THEME_GROUPS.ADRENALINE.map(cat => <InterestButton key={cat} cat={cat} />)}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {step === 3 && (
                <div className="animate-in fade-in slide-in-from-bottom-8 duration-500">
                    <div className="mb-10 p-6 bg-red-900/10 border border-red-500/20 rounded-3xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-4 opacity-20">
                            <ShieldAlert className="w-24 h-24 text-red-500" />
                        </div>
                        <span className="text-[10px] font-bold text-red-500 uppercase tracking-widest bg-red-500/10 px-2 py-1 rounded border border-red-500/20">Dernière question</span>
                        <h2 className="text-3xl font-[1000] text-white uppercase tracking-tight mt-4 leading-none">
                            Contenu<br/>Choquant.
                        </h2>
                        <p className="text-xs text-red-200/60 font-medium mt-4 leading-relaxed max-w-[80%]">
                            Certains reportages (guerre, faits divers) montrent la réalité brute sans filtre.<br/><br/>
                            <span className="text-white font-bold">Par défaut, je masque tout ça.</span> Active ces sujets uniquement si tu es sûr de toi.
                        </p>
                    </div>

                    <div className="space-y-2">
                        {THEME_GROUPS.SENSITIVE.map(cat => <DangerToggle key={cat} cat={cat} />)}
                    </div>
                </div>
            )}

            {step === 4 && (
                <div className="h-full flex flex-col justify-center items-center text-center animate-in zoom-in duration-500">
                    <div className="w-20 h-20 border-4 border-white/10 border-t-white rounded-full animate-spin mb-8" />
                    <h2 className="text-3xl font-[1000] text-white uppercase tracking-tighter mb-4">
                        FINALISATION...
                    </h2>
                    <div className="space-y-2 text-left bg-zinc-900 p-6 rounded-2xl border border-white/5 w-full max-w-xs">
                        <div className="flex items-center gap-3">
                            <Check className="w-4 h-4 text-emerald-500" />
                            <span className="text-xs font-mono text-zinc-400 uppercase">Sources : CONNECTÉES</span>
                        </div>
                        <div className="flex items-center gap-3">
                            <Check className="w-4 h-4 text-emerald-500" />
                            <span className="text-xs font-mono text-zinc-400 uppercase">Filtres : ACTIFS</span>
                        </div>
                        <div className="flex items-center gap-3">
                            <Check className="w-4 h-4 text-emerald-500" />
                            <span className="text-xs font-mono text-zinc-400 uppercase">Assistant Mimo : PRÊT</span>
                        </div>
                    </div>
                </div>
            )}
        </div>

        {/* Footer Actions */}
        <div className="p-6 border-t border-white/5 bg-black">
            {step < 4 ? (
                <button 
                    onClick={step === 3 ? handleFinish : handleNext}
                    className="w-full py-5 bg-white text-black rounded-2xl font-black uppercase text-sm tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-zinc-200 transition-all active:scale-95"
                >
                    {step === 0 ? "C'EST PARTI" : (step === 3 ? "LANCER L'APP" : "CONTINUER")} 
                    <ArrowRight className="w-5 h-5" />
                </button>
            ) : (
                <div className="text-center text-[10px] font-mono text-zinc-600 uppercase animate-pulse">
                    Accès au réseau en cours...
                </div>
            )}
        </div>
    </div>
  );
};

